function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

function cleanJsonResponse(text: string): string {
  if (!text) return "{}";
  let cleaned = text.trim();
  cleaned = cleaned.replace(/^```json\s*/, '').replace(/```$/, '');
  return cleaned.trim();
}

const perspectiveSchema = {
  type: Type.OBJECT,
  properties: {
    verdict: { type: Type.STRING, description: "A one-sentence punchy summary." },
    analysis: { type: Type.STRING, description: "At least 2 dense, academic paragraphs of analysis." }
  },
  required: ["verdict", "analysis"]
};

const sourceSchema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING },
    uri: { type: Type.STRING }
  },
  required: ["title", "uri"]
};

const oracleResponseSchema = {
  type: Type.OBJECT,
  properties: {
    type: { type: Type.STRING, description: "SINGLE or COMPARISON" },
    category: { type: Type.STRING },
    title: { type: Type.STRING },
    verdict: { type: Type.STRING },
    detailedAnalysis: { type: Type.STRING, description: "Primary philosophical response. MUST BE AT LEAST 3-4 DENSE PARAGRAPHS." },
    genre: { type: Type.STRING },
    sources: { type: Type.ARRAY, items: sourceSchema },
    comparison: {
      type: Type.OBJECT,
      properties: {
        optionA: { type: Type.OBJECT, properties: { title: { type: Type.STRING }, description: { type: Type.STRING } } },
        optionB: { type: Type.OBJECT, properties: { title: { type: Type.STRING }, description: { type: Type.STRING } } },
        winner: { type: Type.STRING, description: "Exactly 'A' or 'B'" }
      }
    },
    perspectives: {
      type: Type.OBJECT,
      properties: {
        psychoanalysis: perspectiveSchema,
        gestalt: perspectiveSchema,
        russian_philosophy: perspectiveSchema,
        german_philosophy: perspectiveSchema,
        existential: perspectiveSchema,
        theological: perspectiveSchema,
        buddhist: perspectiveSchema,
        post_modern: perspectiveSchema
      }
    }
  },
  required: ["type", "category", "title", "verdict", "detailedAnalysis", "perspectives"]
};

function determineSubStyle(response: OracleResponse, chaosScore: number, mode: 'SUPREMATIST' | 'IMPRESSIONIST'): string {
    const titleLower = response.title?.toLowerCase() || "";
    const isMedia = response.category === 'MEDIA' || titleLower.includes('movie');
    const isBook = response.category === 'BOOKS' || titleLower.includes('book');
    const isArch = response.category === 'ARCHITECTURE';
    const isScience = response.category === 'SCIENCE';

    if (isMedia) return chaosScore <= 50 ? (mode === 'SUPREMATIST' ? 'BAUHAUS_POSTER' : 'VINTAGE_POSTER') : 'CINEMATIC_SHOT';
    if (isBook) return chaosScore <= 50 ? (mode === 'SUPREMATIST' ? 'CONSTRUCTIVISM' : 'VINTAGE_POSTER') : 'LITERARY_POSTER';
    if (isArch) return mode === 'SUPREMATIST' ? 'DECONSTRUCTIVISM' : 'PENCIL_SKETCH';
    if (isScience) return mode === 'SUPREMATIST' ? 'TECHNICAL_DIAGRAM' : 'NATURAL_STUDY';

    if (mode === 'SUPREMATIST') return chaosScore < 40 ? 'CUBISM' : (chaosScore < 70 ? 'CONSTRUCTIVISM' : 'SUPREMATISM');
    return chaosScore < 40 ? 'IMPRESSIONISM' : (chaosScore < 70 ? 'POST_IMPRESSIONISM' : 'SYMBOLISM');
}

function buildImagePrompt(response: OracleResponse, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST', subStyle: string): string {
  const safeTitle = response.title || "The Unnamed Vision"; 
  if (response.type === 'COMPARISON' && response.comparison) {
      const { optionA, optionB } = response.comparison;
      return artStyle === 'SUPREMATIST' 
        ? `Split screen geometric composition. Left: "${optionA.title}". Right: "${optionB.title}". Suprematist style, high contrast.`
        : `Split screen oil painting. Left: "${optionA.title}". Right: "${optionB.title}". Impressionist style, rich lighting.`;
  }
  return `Artistic interpretation of "${safeTitle}" in style of ${subStyle}. High quality fine art piece. Deep, symbolic, non-literal representation.`;
}

async function generateImagePollinations(prompt: string): Promise<{ image?: string }> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [{ text: prompt }]
            },
            config: {
                imageConfig: {
                    aspectRatio: "1:1"
                }
            }
        });
        const candidate = response.candidates?.[0];
        if (candidate?.content?.parts) {
            for (const part of candidate.content.parts) {
                if (part.inlineData) {
                    return { image: part.inlineData.data };
                }
            }
        }
    } catch (e) { 
        console.error("Gemini Image Generation Failed:", e); 
    }
    return {};
}

export const speakText = async (text: string, language: 'EN' | 'RU' = 'EN') => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: language === 'RU' ? 'Puck' : 'Kore' } } }
            }
        });
        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (base64Audio) {
            const context = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
            const audioBuffer = await decodeAudioData(
              decodeBase64(base64Audio),
              context,
              24000,
              1
            );
            const source = context.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(context.destination);
            source.start();
            return { context, source };
        }
    } catch (e) { console.error(e); }
    throw new Error("Audio failed");
};

export const translateOracleResponse = async (data: OracleResponse, targetLang: 'EN' | 'RU'): Promise<OracleResponse> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const payload = JSON.parse(JSON.stringify(data)); 
    const originalImage = payload.base64Image;
    const originalSources = payload.sources;
    delete payload.base64Image;

    try {
        const response = await ai.models.generateContent({
            model: textModel,
            contents: `Translate this JSON to ${targetLang === 'RU' ? 'Russian' : 'English'}. Maintain philosophical gravity and complex sentence structure. JSON: ${JSON.stringify(payload)}`,
            config: { 
              responseMimeType: "application/json",
              responseSchema: oracleResponseSchema
            }
        });

        const cleanedText = cleanJsonResponse(response.text || "{}");
        const parsed = JSON.parse(cleanedText);
        return { 
          ...parsed, 
          base64Image: originalImage, 
          sources: parsed.sources && parsed.sources.length > 0 ? parsed.sources : originalSources,
          language: targetLang 
        };
    } catch (e) {
        console.warn("Translation failed", e);
        return { ...data, language: targetLang };
    }
};

export const consultOracle = async (query: string, chaosPercentage: number, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST' = 'SUPREMATIST', language: 'EN' | 'RU' = 'EN'): Promise<OracleResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const systemInstruction = `You are The Oracle of Chance, an anti-algorithmic decision engine and philosophical excavator.

    Your mission: Analyze the user's query with extreme intellectual depth, avoiding clichés. 

    Rules for Writing:
    1. STYLE: High-academic, poetic, and slightly detached. Use terminology from continental philosophy.
    2. LENGTH: The 'detailedAnalysis' MUST be at least 3-4 dense paragraphs (roughly 400-600 words total). Each paragraph should explore a different ontological layer.
    3. REFERENCES: Explicitly reference thinkers like Heidegger, Berdyaev, Deleuze, Simone de Beauvoir, Schopenhauer, or Solovyov where relevant.
    4. PERSPECTIVES: Each specific perspective (Psychoanalysis, Russian Philosophy, etc.) must provide a unique, sophisticated critique that doesn't repeat the main analysis.
    5. COMPARISONS: If the user asks for a choice, provide a clear winner but explain it as a triumph of one metaphysical principle over another.
    6. Language: Use the requested language (${language}) but maintain the complex, sophisticated tone.
    7. SOURCES: Use googleSearch to find actual academic or high-quality sources that support your philosophical claims.

    Output valid JSON strictly following the provided schema.`;

  try {
    const response = await ai.models.generateContent({
      model: textModel,
      contents: query,
      config: { 
        systemInstruction, 
        tools: [{ googleSearch: {} }], 
        temperature: (chaosPercentage / 100) + 0.1, 
        responseMimeType: "application/json",
        responseSchema: oracleResponseSchema
      },
    });

    const cleanedText = cleanJsonResponse(response.text || "{}");
    const parsed = JSON.parse(cleanedText) as OracleResponse;

    if (!parsed.detailedAnalysis) parsed.detailedAnalysis = parsed.verdict || "Revelation pending.";

    const subStyle = determineSubStyle(parsed, chaosPercentage, artStyle);
    parsed.imageStyleLabel = subStyle.replace('_', '-');

    const imgResult = await generateImagePollinations(buildImagePrompt(parsed, artStyle, subStyle));
    parsed.base64Image = imgResult.image;

    const candidate = response.candidates?.[0];
    if (candidate?.groundingMetadata?.groundingChunks) {
      const fetchedSources: OracleSource[] = candidate.groundingMetadata.groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({
          title: chunk.web.title || "Grounding Link",
          uri: chunk.web.uri
        }));
      if (fetchedSources.length > 0) parsed.sources = fetchedSources;
    }

    return { ...parsed, language };
  } catch (e) {
    console.error("Critical Oracle Error:", e);
    return {
      type: "SINGLE",
      category: "LIFE",
      title: language === 'RU' ? "Кризис Смысла" : "Crisis of Meaning",
      verdict: language === 'RU' ? "Тишина — это тоже ответ." : "Silence is also an answer.",
      detailedAnalysis: language === 'RU' 
        ? "Произошла алгоритмическая сингулярность. Поток данных прерван, напоминая нам о хрупкости человеческого познания в эпоху цифрового шума. Как писал Хайдеггер, 'просвет' (Lichtung) иногда закрывается, оставляя нас в ожидании нового проблеска бытия."
        : "An algorithmic singularity has occurred. The data stream is severed, reminding us of the fragility of human cognition in the age of digital noise. As Heidegger suggested, the 'clearing' (Lichtung) sometimes closes, leaving us in wait for a new glimmer of Being.",
      perspectives: {},
      language
    } as any;
  }
};

export const regenerateOracleImage = async (response: OracleResponse, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST', chaosScore: number) => {
    const subStyle = determineSubStyle(response, chaosScore, artStyle);
    const result = await generateImagePollinations(buildImagePrompt(response, artStyle, subStyle));
    return { image: result.image, label: subStyle.replace('_', '-') };
};

