        </div>

        <NavButton onClick={() => setShowHistory(true)}>
          <Icons.History />
        </NavButton>
      </div>
    </>
  );

  const HistorySidebar = (
    <div className={`fixed inset-0 z-[1000] flex justify-end transition-all ${showHistory ? 'visible opacity-100' : 'invisible opacity-0'}`}>
      <div className={`fixed inset-0 bg-black/60 backdrop-blur-sm transition-opacity duration-300 ${showHistory ? 'opacity-100' : 'opacity-0'}`} onClick={() => setShowHistory(false)} />
      <div className={`relative z-[1010] w-full max-sm:max-w-full max-w-sm h-full p-6 md:p-12 shadow-2xl overflow-y-auto flex flex-col transition-transform duration-500 transform ${showHistory ? 'translate-x-0' : 'translate-x-full'} ${isRenoir ? 'bg-[#1e0a0a] text-amber-100 border-l border-amber-900/10' : 'bg-white text-black border-l border-black/5'}`}>
         <div className="flex justify-between items-center mb-6 md:mb-10">
            <h2 className="text-xl md:text-2xl font-black uppercase tracking-tighter">{t.history}</h2>
            <button onClick={() => setShowHistory(false)} className="p-2 hover:rotate-90 transition-transform bg-current/5 rounded-full"><Icons.Close /></button>
         </div>
         <div className="space-y-4 md:space-y-6 flex-1">
            {history.length === 0 ? (
              <div className="text-center py-24 opacity-20 text-[10px] font-black uppercase tracking-widest">{t.voidEmpty}</div>
            ) : history.map(item => (
              <button key={item.id} onClick={() => { stopAudio(); setState({ ...state, status: 'REVEALED', response: item.response, query: item.query, logicScore: item.logicScore, chaosScore: item.chaosScore }); setShowHistory(false); }} className="block w-full text-left p-4 md:p-6 border border-current/10 rounded-2xl md:rounded-3xl hover:bg-current/5 hover:border-current/20 transition-all group active:scale-95 shadow-sm">
                <div className="text-[9px] opacity-40 mb-2 font-black tracking-widest uppercase flex justify-between items-center">
                  <span>{new Date(item.timestamp).toLocaleTimeString()}</span>
                  <span className="opacity-0 group-hover:opacity-100 transition-opacity">→</span>
                </div>
                <div className="text-sm md:text-base font-bold uppercase truncate">{item.query}</div>
              </button>
            ))}
         </div>
      </div>
    </div>
  );

  if (state.status === 'ERROR') {
    return (
      <div className={`min-h-screen w-full flex flex-col items-center justify-center p-6 text-center ${isRenoir ? 'bg-[#0f0505] text-amber-100' : 'bg-white text-black'}`}>
         <h1 className="text-2xl font-black uppercase tracking-widest mb-4">Paradox Encountered</h1>
         <p className="text-xs opacity-60 mb-8 max-w-xs">{state.error || "The Void is unable to synthesize your query."}</p>
         <button onClick={() => setState(s => ({ ...s, status: 'IDLE' }))} className="px-8 py-3 border border-current font-black uppercase tracking-[0.3em] hover:bg-current hover:text-white transition-all text-[10px]">Recalibrate</button>
      </div>
    );
  }

  if (state.status === 'THINKING') return (
    <div className="relative">
      <LoadingScreen theme={theme} language={uiLanguage} />
      <button onClick={() => setState(s => ({ ...s, status: 'IDLE' }))} className="fixed bottom-6 left-1/2 -translate-x-1/2 px-4 py-1.5 bg-black/5 text-[8px] font-black uppercase tracking-widest rounded-full opacity-30 hover:opacity-100 transition-opacity z-[600]">Force Reset</button>
    </div>
  );

  if (state.status === 'REVEALED' && state.response) {
    const r = state.response;
    const isComparison = r.type === 'COMPARISON' && r.comparison;

    return (
      <div className={`min-h-screen w-full flex flex-col items-center pt-20 md:pt-28 pb-10 px-4 md:px-8 overflow-y-auto ${isRenoir ? 'bg-[#0f0505] text-amber-100 font-serif' : 'bg-white text-black font-sans'}`}>
        {GlobalUI}
        {HistorySidebar}

        <div ref={captureRef} className={`w-full max-w-5xl transition-all duration-700 ${isTranslating ? 'blur-md' : 'blur-0'}`}>
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 lg:gap-12 items-start">
            <div className="flex flex-col items-center w-full sticky top-24 max-lg:relative max-lg:top-0">
              <RatioIndicator logicScore={state.logicScore} chaosScore={state.chaosScore} category={r.category as any} theme={theme} language={uiLanguage} />
              <div className={`relative w-full max-w-sm aspect-square border shadow-2xl overflow-hidden ${isRenoir ? 'border-amber-900/20 rounded-[1.5rem]' : 'border-black/5'}`}>
                {isImageLoading && <div className="absolute inset-0 z-20 bg-black/40 backdrop-blur-lg flex items-center justify-center"><div className="w-6 h-6 border-2 border-white border-t-transparent rounded-full animate-spin"/></div>}
                {r.base64Image ? <img src={`data:image/png;base64,${r.base64Image}`} className="w-full h-full object-cover" alt="Oracle Vision" /> : <div className="h-full flex items-center justify-center opacity-20 text-[9px] font-black uppercase tracking-widest">{t.imageLost}</div>}
                <div className="absolute top-3 left-3 flex flex-col gap-1.5">
                   <span className={`px-2 py-0.5 text-[7px] font-black uppercase tracking-widest shadow-xl ${isRenoir ? 'bg-amber-800 text-white' : 'bg-black text-white'}`}>{r.category}</span>
                   {r.imageStyleLabel && <span className={`px-2 py-0.5 text-[6px] font-bold uppercase tracking-widest shadow-xl backdrop-blur-md ${isRenoir ? 'bg-amber-600/90 text-white' : 'bg-red-600 text-white'}`}>{r.imageStyleLabel}</span>}
                </div>
              </div>
            </div>

            <div className="flex flex-col items-center lg:items-start w-full">
              <h1 className="text-xl md:text-2xl lg:text-3xl font-black uppercase text-center lg:text-left mb-4 leading-tight tracking-tighter w-full">{r.title}</h1>
              {isComparison && r.comparison && (
                <div className={`w-full flex border mb-4 rounded-[1.25rem] overflow-hidden shadow-md ${isRenoir ? 'border-amber-900/10 bg-amber-900/5' : 'border-black/5 bg-gray-50'}`}>
                  {['A', 'B'].map((key) => {
                    const opt = key === 'A' ? r.comparison!.optionA : r.comparison!.optionB;
                    const isWinner = r.comparison!.winner === key;
                    return (
                      <div key={key} className={`flex-1 p-4 border-current/10 text-center transition-all ${isWinner ? 'bg-current/5 font-black' : 'opacity-40 grayscale'} ${key === 'A' ? 'border-r' : ''}`}>
                        <div className="text-[7px] mb-1 uppercase tracking-widest font-black opacity-50">{key === 'A' ? t.optionA : t.optionB}</div>
                        <div className="text-[11px] md:text-xs font-black uppercase leading-tight">{opt.title}</div>
                        {isWinner && <div className="mt-1.5 text-[7px] font-black text-red-600 uppercase tracking-widest animate-pulse">★ {t.winner}</div>}
                      </div>
                    );
                  })}
                </div>
              )}

              <div className={`w-full p-5 border mb-5 relative ${isRenoir ? 'bg-[#1e0a0a]/80 border-amber-900/10 rounded-[1.25rem] shadow-xl' : 'bg-white border-black/5'}`}>
                <div className="flex justify-between items-center mb-3 border-b border-current/5 pb-1.5">
                  <h3 className="text-[9px] font-black uppercase tracking-widest opacity-40">{t.verdict}</h3>
                  <select value={activeFramework} onChange={(e) => setActiveFramework(e.target.value as FrameworkType)} className="text-[8px] font-black uppercase bg-transparent outline-none cursor-pointer border-b border-current/10 hover:border-current transition-all">
                      {Object.keys(t.frameworks).map(k => <option key={k} value={k} className="text-black">{(t.frameworks as any)[k]}</option>)}
                  </select>
                </div>
                <div className="text-xs md:text-sm leading-relaxed text-justify whitespace-pre-wrap font-medium">
                   {activeAnalysis || "Awaiting revelation..."}
                </div>
              </div>

              <div className="w-full flex flex-col gap-2.5">
                 <button onClick={() => setShowFullVerdict(true)} className={`w-full py-3 text-[10px] font-black uppercase tracking-[0.25em] transition-all hover:brightness-110 active:scale-95 shadow-xl ${isRenoir ? 'bg-[#78350f] text-white rounded-[0.85rem]' : 'bg-black text-white'}`}>
                    {t.readVerdict}
                 </button>
                 <div className="flex gap-2.5">
                    <div className="flex-1 relative">
                       <button onClick={() => setShowSaveOptions(!showSaveOptions)} className={`w-full py-3 text-[9px] font-black uppercase border flex items-center justify-center gap-2 rounded-[0.85rem] transition-all ${isRenoir ? 'border-amber-900/10 text-amber-200 hover:bg-amber-900/10 active:bg-amber-100/10 shadow-sm' : 'border-black/5 text-black hover:bg-black hover:text-white active:bg-zinc-800 shadow-sm'}`}>
                          <Icons.Download /> {t.saveArtifact}
                       </button>
                       {showSaveOptions && (
                         <div ref={saveOptionsRef} className={`absolute bottom-full left-0 w-full mb-2 p-1 border rounded-[1rem] shadow-2xl animate-in slide-in-from-bottom-2 flex flex-col z-[110] backdrop-blur-xl ${isRenoir ? 'bg-[#271005]/95 border-amber-900/20 text-amber-50' : 'bg-white/95 border-black/5 text-black'}`}>
                            <button onClick={saveArtifactAsImage} className="py-2.5 text-[9px] font-black uppercase hover:bg-red-600 hover:text-white transition-all rounded-[0.6rem] text-center">{t.saveCard}</button>
                            <button onClick={() => { const l=document.createElement('a'); l.download='vision.png'; l.href=`data:image/png;base64,${r.base64Image}`; l.click(); setShowSaveOptions(false); }} className="py-2.5 text-[9px] font-black uppercase hover:bg-red-600 hover:text-white transition-all rounded-[0.6rem] text-center">{t.saveImage}</button>
                         </div>
                       )}
                    </div>
                    <button onClick={() => setState(s => ({ ...s, status: 'IDLE' }))} className={`flex-1 py-3 text-[9px] font-black uppercase border rounded-[0.85rem] transition-all ${isRenoir ? 'border-amber-900/10 text-amber-200 hover:bg-amber-900/10 active:bg-amber-100/10 shadow-sm' : 'border-black/5 text-black hover:bg-black hover:text-white active:bg-zinc-800 shadow-sm'}`}>{t.newQuery}</button>
                 </div>
              </div>

              <div className="mt-6 pt-5 border-t border-current/5 w-full">
                <div className="flex flex-wrap justify-center lg:justify-start gap-3 items-center">
                  <span className="text-[8px] font-black uppercase tracking-[0.3em] opacity-30">{t.sources}</span>
                  <div className="flex flex-wrap gap-3">
                    {r.sources && r.sources.length > 0 ? r.sources.map((s, i) => (
                      <a key={i} href={s.uri} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1.5 text-[8px] font-black uppercase border-b border-current/10 pb-0.5 hover:border-current transition-all max-w-[150px]">
                         <Icons.ExternalLink /> <span className="truncate">{s.title}</span>
                      </a>
                    )) : <span className="text-[8px] opacity-20 font-black uppercase tracking-widest">{t.voidEmpty}</span>}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        {showFullVerdict && (
          <div className="fixed inset-0 z-[1000] flex items-center justify-center p-0 md:p-6 lg:p-10 bg-black/60 backdrop-blur-md animate-in fade-in duration-500" onClick={() => setShowFullVerdict(false)}>
            <div className={`relative z-[1010] w-full h-full md:h-[90vh] max-w-7xl flex flex-col lg:flex-row shadow-2xl overflow-hidden md:rounded-[2rem] border border-white/10 transition-all bg-clip-padding ${isRenoir ? 'bg-amber-950/90' : 'bg-zinc-950/90'}`} onClick={e => e.stopPropagation()}>
              <div className="flex-1 overflow-y-auto p-6 md:p-12 lg:p-16 text-white order-2 lg:order-1 relative custom-scrollbar flex flex-col">
                 <button onClick={() => setShowFullVerdict(false)} className="absolute top-6 right-6 w-10 h-10 flex items-center justify-center hover:rotate-90 hover:bg-white hover:text-black transition-all bg-white/10 text-white rounded-full z-20"><Icons.Close /></button>
                 <h2 className="text-xl md:text-3xl lg:text-4xl font-black uppercase mb-8 tracking-tighter border-b border-white/10 pb-6">{r.title}</h2>
                 <div className="text-sm md:text-base lg:text-lg leading-relaxed text-justify opacity-95 font-serif max-w-4xl tracking-wide p-2 rounded-xl">
                    {activeAnalysis.split('\n\n').map((p, i) => (
                      <p key={i} className="mb-8 first-letter:text-4xl md:first-letter:text-6xl lg:first-letter:text-7xl first-letter:font-black first-letter:float-left first-letter:mr-4 first-letter:leading-[0.8] first-letter:text-red-500">{p}</p>
                    ))}
                 </div>
              </div>
              <div className="w-full lg:w-72 p-4 md:p-6 lg:p-8 flex flex-col border-b lg:border-b-0 lg:border-l border-white/10 bg-black/40 backdrop-blur-2xl order-1 lg:order-2 shrink-0 overflow-y-auto custom-scrollbar">
                 <div className="hidden lg:flex justify-between items-center mb-8">
                    <h3 className="text-[10px] font-black uppercase tracking-[0.4em] opacity-40 text-white">Aspects</h3>
                 </div>
                 <div className="flex lg:flex-col gap-2 overflow-x-auto lg:overflow-x-visible pb-2 lg:pb-0 scrollbar-hide">
                    {Object.keys(t.frameworks).map((key) => (
                      <button 
                        key={key} 
                        onClick={() => setActiveFramework(key as FrameworkType)} 
                        className={`whitespace-nowrap px-4 py-2.5 text-[8px] font-black uppercase text-left tracking-widest border transition-all rounded-lg ${
                          activeFramework === key 
                            ? 'bg-white text-black border-white shadow-xl scale-[1.02]' 
                            : 'bg-white/5 text-white/40 border-white/5 hover:bg-white/10 hover:border-white/20 hover:text-white'
                        }`}
                      >
                        {(t.frameworks as any)[key]}
                      </button>
                    ))}
                 </div>
                 <button onClick={() => setShowFullVerdict(false)} className="mt-8 lg:mt-10 hidden lg:block w-full py-3 border border-white/20 text-white hover:bg-white hover:text-black text-[9px] font-black uppercase tracking-[0.3em] transition-all rounded-[0.85rem] shadow-xl">{t.closeVerdict}</button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className={`h-screen w-full flex flex-col items-center justify-center p-4 overflow-hidden relative ${isRenoir ? 'bg-[#0f0505] text-amber-100 font-serif' : 'bg-white text-black font-sans'}`}>
      <ThemeBackground theme={theme} />
      {GlobalUI}
      {HistorySidebar}

      <div className={`z-10 w-full max-w-4xl text-center flex flex-col items-center justify-center animate-in fade-in duration-1000 h-full ${isTranslating ? 'blur-lg' : 'blur-0'} transition-all`}>
        <div className="flex flex-col items-center justify-center space-y-6 md:space-y-8 w-full max-w-2xl">
          <h1 className="text-2xl md:text-3xl lg:text-4xl font-light uppercase leading-[0.9] tracking-tighter whitespace-pre-wrap select-none">{t.title}</h1>
          <form onSubmit={e => { e.preventDefault(); runQuery(inputRef.current?.value || ""); }} className="w-full flex flex-col items-center gap-6 md:gap-8">
            <input 
              ref={inputRef} placeholder={t.placeholder} onChange={handleInputChange}
              className={`w-full bg-transparent border-b ${isRenoir ? 'border-amber-900/30 placeholder:text-amber-900/10' : 'border-black/10 placeholder:text-gray-200'} p-2 md:p-3 text-center text-lg md:text-2xl font-light focus:outline-none transition-all focus:tracking-wider max-w-lg`} 
            />
            <div className="flex flex-col items-center gap-3 w-full">
              <button 
                type="button" 
                onClick={() => setIsManual(!isManual)} 
                className={`flex items-center gap-2 px-5 py-1.5 rounded-full text-[8px] md:text-[9px] font-black uppercase tracking-widest border transition-all shadow-lg hover:scale-105 active:scale-95 ${
                  isManual 
                    ? (isRenoir ? 'bg-amber-100/15 border-amber-100/40 text-amber-100' : 'bg-zinc-100 border-black/40 text-black') 
                    : 'opacity-20 border-current hover:opacity-100'
                }`}
              >
                <Icons.Settings /> {t.manualCalibration}
              </button>
              <div className={`w-full max-w-xs overflow-hidden transition-all duration-400 ${isManual ? 'max-h-32 opacity-100 mt-1' : 'max-h-0 opacity-0 pointer-events-none'}`}>
                <div className="p-4 bg-current/5 rounded-2xl border border-current/5 space-y-4 backdrop-blur-sm">
                  <div className="flex justify-between text-[8px] font-black uppercase opacity-50 tracking-widest"><span>{t.logic} {state.logicScore}%</span><span>{t.chaos} {state.chaosScore}%</span></div>
                  <input type="range" min="0" max="100" value={state.chaosScore} onChange={e => { const c = parseInt(e.target.value); setState(s => ({ ...s, chaosScore: c, logicScore: 100 - c })); }} className="w-full h-1 bg-gray-200 rounded-full appearance-none cursor-pointer accent-current hover:brightness-110 transition-all" />
                </div>
              </div>
            </div>
            <button type="submit" className={`w-20 h-20 md:w-24 md:h-24 rounded-full font-black uppercase shadow-2xl transition-all hover:scale-110 active:scale-90 flex items-center justify-center relative group ${isRenoir ? 'bg-gradient-to-br from-[#78350f] to-[#451a03] text-amber-50 border border-amber-600/10' : 'bg-black text-white'}`}>
              <span className={`relative z-10 text-center px-1.5 ${uiLanguage === 'RU' ? 'text-[9px] md:text-[10px] tracking-tight' : 'text-base md:text-lg'}`}>{t.ask}</span>
              <div className="absolute inset-0 bg-white opacity-0 group-hover:opacity-10 rounded-full transition-opacity" />
            </button>
            <div className="flex flex-wrap justify-center gap-1.5 md:gap-2 opacity-30 hover:opacity-100 transition-all duration-500 max-w-xl px-4">
              {suggestions.map(s => (
                <button 
                  key={s} 
                  type="button" 
                  onClick={() => { if(inputRef.current) inputRef.current.value = s; runQuery(s); }} 
                  className={`px-3 py-1.5 text-[7px] md:text-[8px] border font-black uppercase rounded-full transition-all shadow-sm active:scale-95 ${
                    isRenoir 
                      ? 'border-amber-900/30 text-amber-900/70 hover:bg-amber-900 hover:text-white' 
                      : 'border-black/10 text-black/70 hover:bg-black hover:text-white'
                  }`}
                >
                  {s}
                </button>
              ))}
            </div>
          </form>
        </div>
      </div>
      <footer className="absolute bottom-4 text-[9px] uppercase tracking-[0.5em] opacity-10 font-black select-none pointer-events-none">{t.footer}</footer>
    </div>
  );
};

