                <div className="p-3 bg-current/5 rounded-2xl border border-current/5 space-y-3 backdrop-blur-sm">
                  <div className="flex justify-between text-[7px] font-black uppercase opacity-50 tracking-widest"><span>{t.logic} {state.logicScore}%</span><span>{t.chaos} {state.chaosScore}%</span></div>
                  <input type="range" min="0" max="100" value={state.chaosScore} onChange={e => { const c = parseInt(e.target.value); setState(s => ({ ...s, chaosScore: c, logicScore: 100 - c })); }} className="w-full h-1 bg-gray-200 rounded-full appearance-none cursor-pointer accent-current hover:brightness-110 transition-all" />
                </div>
              </div>
            </div>
            <button type="submit" className={`w-20 h-20 md:w-24 md:h-24 font-black uppercase shadow-2xl transition-all hover:scale-110 active:scale-90 flex items-center justify-center relative group ${theme === 'SUPREMATIST' ? 'rounded-none' : 'rounded-full'} ${isRenoir ? 'bg-gradient-to-br from-[#78350f] to-[#451a03] text-amber-50 border border-amber-600/10' : 'bg-black text-white'}`}>
              <span className={`relative z-10 text-center px-1.5 ${uiLanguage === 'RU' ? 'text-[9px] md:text-[10px] tracking-tight' : 'text-base md:text-lg'}`}>{t.ask}</span>
              <div className="absolute inset-0 bg-white opacity-0 group-hover:opacity-10 rounded-full transition-opacity" />
            </button>
            <div className="flex flex-wrap justify-center gap-1.5 md:gap-2 opacity-30 hover:opacity-100 transition-all duration-500 max-w-lg px-4">
              {suggestions.map(s => (
                <button 
                  key={s} 
                  type="button" 
                  onClick={() => { if(inputRef.current) inputRef.current.value = s; runQuery(s); }} 
                  className={`px-3 py-1.5 text-[7px] md:text-[8px] border font-black uppercase rounded-full transition-all shadow-sm active:scale-95 ${
                    isRenoir 
                      ? 'border-amber-900/30 text-amber-900/70 hover:bg-amber-900 hover:text-white' 
                      : 'border-black/10 text-black/70 hover:bg-black hover:text-white'
                  }`}
                >
                  {s}
                </button>
              ))}
            </div>
          </form>
        </div>
      </div>
      <footer className="absolute bottom-4 text-[9px] uppercase tracking-[0.5em] opacity-10 font-black select-none pointer-events-none">{t.footer}</footer>
    </div>
  );
};

