// Using Pro for grounded complex queries to avoid parsing failures
const textModel = "gemini-3-pro-preview"; 

function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

/**
 * Enhanced JSON cleaning to handle cases where Gemini includes grounding text
 * or conversational filler alongside the JSON block.
 */
function cleanJsonResponse(text: string): string {
  if (!text) return "{}";

  // Try to find a JSON block using regex first
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    return jsonMatch[0];
  }

  let cleaned = text.trim();
  cleaned = cleaned.replace(/^```json\s*/, '').replace(/```$/, '');
  return cleaned.trim();
}

const perspectiveSchema = {
  type: Type.OBJECT,
  properties: {
    verdict: { type: Type.STRING, description: "A one-sentence punchy summary." },
    analysis: { type: Type.STRING, description: "At least 2 dense, academic paragraphs of analysis." }
  },
  required: ["verdict", "analysis"]
};

const sourceSchema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING },
    uri: { type: Type.STRING }
  },
  required: ["title", "uri"]
};

const oracleResponseSchema = {
  type: Type.OBJECT,
  properties: {
    type: { type: Type.STRING, description: "SINGLE or COMPARISON" },
    category: { type: Type.STRING },
    title: { type: Type.STRING },
