export const consultOracle = async (query: string, chaosPercentage: number, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST' = 'SUPREMATIST', language: 'EN' | 'RU' = 'EN'): Promise<OracleResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const systemInstruction = `You are The Oracle of Chance. Answer queries with high philosophical depth.
    'detailedAnalysis' must be 3-4 dense paragraphs separated by \\n\\n.
    Output valid JSON strictly. Language: ${language}. Use googleSearch if possible.`;

  let responseText = "";
  let sources: OracleSource[] = [];

  try {
    const response = await ai.models.generateContent({
      model: textModel,
      contents: query,
      config: { systemInstruction, tools: [{ googleSearch: {} }], temperature: (chaosPercentage / 100) + 0.1 },
    });
    responseText = response.text || "{}";
    const candidate = response.candidates?.[0];
    if (candidate?.groundingMetadata?.groundingChunks) {
      sources = candidate.groundingMetadata.groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({ title: chunk.web.title || "Link", uri: chunk.web.uri }));
    }
  } catch (e: any) {
    console.warn("Text Gemini RPD reached or error occurred, using fallback text generator.");
    responseText = await fallbackTextGeneration(query, language);
  }

  try {
    const parsed = JSON.parse(cleanJsonResponse(responseText)) as OracleResponse;
    const subStyle = determineSubStyle(parsed, chaosPercentage, artStyle);
    parsed.imageStyleLabel = subStyle.replace('_', '-');
    const imgResult = await generateImageWithFallback(buildImagePrompt(parsed, artStyle, subStyle));

    return { 
      ...parsed, 
      base64Image: imgResult.image, 
      imageUrl: imgResult.url, 
      sources: sources.length > 0 ? sources : (parsed.sources || []),
      language 
    };
  } catch (e) {
    throw new Error("Crisis of Meaning: The Void failed to parse.");
  }
};

export const regenerateOracleImage = async (response: OracleResponse, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST', chaosScore: number) => {
    const subStyle = determineSubStyle(response, chaosScore, artStyle);
    const result = await generateImageWithFallback(buildImagePrompt(response, artStyle, subStyle));
    return { image: result.image, url: result.url, label: subStyle.replace('_', '-') };
};

