import { GoogleGenAI, Modality, Type } from "@google/genai";
import { OracleResponse, OracleSource } from "../types";

// Declare process for environments without @types/node
declare var process: {
  env: {
    API_KEY: string;
  };
};

// Using Pro for primary complex queries
const textModel = "gemini-3-pro-preview"; 

function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

function cleanJsonResponse(text: string): string {
  if (!text) return "{}";
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) return jsonMatch[0];
  let cleaned = text.trim();
  cleaned = cleaned.replace(/^```json\s*/, '').replace(/```$/, '');
  return cleaned.trim();
}

const oracleResponseSchema = {
  type: Type.OBJECT,
  properties: {
    type: { type: Type.STRING },
    category: { type: Type.STRING },
    title: { type: Type.STRING },
    verdict: { type: Type.STRING },
    detailedAnalysis: { type: Type.STRING },
    perspectives: { type: Type.OBJECT }
  },
  required: ["type", "category", "title", "verdict", "detailedAnalysis", "perspectives"]
};

function determineSubStyle(response: OracleResponse, chaosScore: number, mode: 'SUPREMATIST' | 'IMPRESSIONIST'): string {
    const titleLower = (response.title || "").toLowerCase();
    const isMedia = response.category === 'MEDIA' || titleLower.includes('movie');
    const isBook = response.category === 'BOOKS' || titleLower.includes('book');
    const isArch = response.category === 'ARCHITECTURE';
    const isScience = response.category === 'SCIENCE';

    if (isMedia) return chaosScore <= 50 ? (mode === 'SUPREMATIST' ? 'BAUHAUS_POSTER' : 'VINTAGE_POSTER') : 'CINEMATIC_SHOT';
    if (isBook) return chaosScore <= 50 ? (mode === 'SUPREMATIST' ? 'CONSTRUCTIVISM' : 'VINTAGE_POSTER') : 'LITERARY_POSTER';
    if (isArch) return mode === 'SUPREMATIST' ? 'DECONSTRUCTIVISM' : 'PENCIL_SKETCH';
    if (isScience) return mode === 'SUPREMATIST' ? 'TECHNICAL_DIAGRAM' : 'NATURAL_STUDY';

    if (mode === 'SUPREMATIST') return chaosScore < 40 ? 'CUBISM' : (chaosScore < 70 ? 'CONSTRUCTIVISM' : 'SUPREMATISM');
    return chaosScore < 40 ? 'IMPRESSIONISM' : (chaosScore < 70 ? 'POST_IMPRESSIONISM' : 'SYMBOLISM');
}

function buildImagePrompt(response: OracleResponse, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST', subStyle: string): string {
  const safeTitle = response.title || "The Unnamed Vision"; 
  if (response.type === 'COMPARISON' && response.comparison) {
      const { optionA, optionB } = response.comparison;
      return artStyle === 'SUPREMATIST' 
        ? `Split screen geometric composition. Left: "${optionA.title}". Right: "${optionB.title}". Suprematist style, high contrast.`
        : `Split screen oil painting. Left: "${optionA.title}". Right: "${optionB.title}". Impressionist style, rich lighting.`;
  }
  return `Artistic interpretation of "${safeTitle}" in style of ${subStyle}. Deep, symbolic, non-literal representation. Atmosphere of ontological weight.`;
}

async function generateImageWithFallback(prompt: string): Promise<{ image?: string; url?: string }> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts: [{ text: prompt }] },
            config: { imageConfig: { aspectRatio: "1:1" } }
        });
        const candidate = response.candidates?.[0];
        if (candidate?.content?.parts) {
            for (const part of candidate.content.parts) {
                if (part.inlineData) return { image: part.inlineData.data };
            }
        }
    } catch (e) { 
        console.warn("Image Gemini RPD reached, falling back to Pollinations."); 
    }
    const seed = Math.floor(Math.random() * 1000000);
    return { url: `https://image.pollinations.ai/prompt/${encodeURIComponent(prompt)}?width=1024&height=1024&nologo=true&seed=${seed}` };
}

/**
 * Fallback Text Generation using Pollinations if Gemini 429 occurs.
 */
async function fallbackTextGeneration(query: string, language: 'EN' | 'RU'): Promise<string> {
    const prompt = `You are the Oracle of Chance. Return ONLY a JSON object answering: "${query}". 
    Format: {
      "type": "SINGLE",
      "category": "LIFE",
      "title": "A Philosophical Title",
      "verdict": "Short summary.",
      "detailedAnalysis": "3-4 long paragraphs about the query, separated by \\n\\n.",
      "perspectives": { "existential": { "verdict": "Existential view.", "analysis": "Detailed analysis." } }
    }
    Language: ${language}. No markdown code blocks, just raw JSON.`;

    try {
        const response = await fetch(`https://text.pollinations.ai/${encodeURIComponent(prompt)}?json=true`);
        return await response.text();
    } catch (e) {
        throw new Error("All text generators failed.");
    }
}

export const speakText = async (text: string, language: 'EN' | 'RU' = 'EN') => {
    // Corrected: Initialization must include the API key.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: language === 'RU' ? 'Puck' : 'Kore' } } }
            }
        });
        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (base64Audio) {
            const context = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
            const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), context, 24000, 1);
            const source = context.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(context.destination);
            source.start();
            return { context, source };
        }
    } catch (e) { console.error(e); }
    throw new Error("Audio failed");
};

export const translateOracleResponse = async (data: OracleResponse, targetLang: 'EN' | 'RU'): Promise<OracleResponse> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const payload = { ...data };
    delete payload.base64Image;
    delete payload.imageUrl;

    try {
        const response = await ai.models.generateContent({
            model: textModel,
            contents: `Translate this Oracle JSON to ${targetLang}. Preserve philosophy. JSON: ${JSON.stringify(payload)}`,
            config: { responseMimeType: "application/json" }
        });
        const parsed = JSON.parse(cleanJsonResponse(response.text || "{}"));
        return { ...parsed, base64Image: data.base64Image, imageUrl: data.imageUrl, language: targetLang };
    } catch (e) {
        return { ...data, language: targetLang };
    }
};

export const consultOracle = async (query: string, chaosPercentage: number, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST' = 'SUPREMATIST', language: 'EN' | 'RU' = 'EN'): Promise<OracleResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const systemInstruction = `You are The Oracle of Chance. Answer queries with high philosophical depth.
    'detailedAnalysis' must be 3-4 dense paragraphs separated by \\n\\n.
    Output valid JSON strictly. Language: ${language}. Use googleSearch if possible.`;

  let responseText = "";
  let sources: OracleSource[] = [];

  try {
    const response = await ai.models.generateContent({
      model: textModel,
      contents: query,
      config: { systemInstruction, tools: [{ googleSearch: {} }], temperature: (chaosPercentage / 100) + 0.1 },
    });
    responseText = response.text || "{}";
    const candidate = response.candidates?.[0];
    if (candidate?.groundingMetadata?.groundingChunks) {
      sources = candidate.groundingMetadata.groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({ title: chunk.web.title || "Link", uri: chunk.web.uri }));
    }
  } catch (e: any) {
    console.warn("Text Gemini RPD reached or error occurred, using fallback text generator.");
    responseText = await fallbackTextGeneration(query, language);
  }

  try {
    const parsed = JSON.parse(cleanJsonResponse(responseText)) as OracleResponse;
    const subStyle = determineSubStyle(parsed, chaosPercentage, artStyle);
    parsed.imageStyleLabel = subStyle.replace('_', '-');
    const imgResult = await generateImageWithFallback(buildImagePrompt(parsed, artStyle, subStyle));

    return { 
      ...parsed, 
      base64Image: imgResult.image, 
      imageUrl: imgResult.url, 
      sources: sources.length > 0 ? sources : (parsed.sources || []),
      language 
    };
  } catch (e) {
    throw new Error("Crisis of Meaning: The Void failed to parse.");
  }
};

export const regenerateOracleImage = async (response: OracleResponse, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST', chaosScore: number) => {
    const subStyle = determineSubStyle(response, chaosScore, artStyle);
    const result = await generateImageWithFallback(buildImagePrompt(response, artStyle, subStyle));
    return { image: result.image, url: result.url, label: subStyle.replace('_', '-') };
};

