export const App: React.FC = () => {
  const [theme, setTheme] = useState<Theme>('SUPREMATIST');
  const [uiLanguage, setUiLanguage] = useState<Language>('EN');
  const [initialChaos] = useState(() => Math.floor(Math.random() * 80) + 10);
  const [state, setState] = useState<OracleState>({ status: 'IDLE', query: '', response: null, logicScore: 100 - initialChaos, chaosScore: initialChaos, attempts: 0 });
  const [activeFramework, setActiveFramework] = useState<FrameworkType>('DEFAULT');
  const [isMuted, setIsMuted] = useState(true);
  const [isTtsLoading, setIsTtsLoading] = useState(false);
  const [isTranslating, setIsTranslating] = useState(false);
  const [showFullVerdict, setShowFullVerdict] = useState(false);
  const [isImageLoading, setIsImageLoading] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [showSaveOptions, setShowSaveOptions] = useState(false);
  const [isManual, setIsManual] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [suggestions, setSuggestions] = useState<string[]>([]);

  const audioContextRef = useRef<AudioContext | null>(null);
  const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const captureRef = useRef<HTMLDivElement>(null);
  const saveOptionsRef = useRef<HTMLDivElement>(null);

  const isRenoir = theme === 'IMPRESSIONIST';
  const t = TRANSLATIONS[uiLanguage];

  useEffect(() => {
    const rotate = () => {
      const corePhilosophical = [
        "Does the algorithm have a soul?", 
        "Is memory resistance?", 
        "The ethics of eternity",
        "The ontological weight of a single pixel",
        "Can silence be computed?",
        "Metaphysics of the binary sunset"
      ];
      const coreComparisons = [
        "Vinyl vs Streaming", 
        "City vs Wilderness", 
        "Manual vs Automatic",
        "Solitude vs Connectivity",
        "Oil paint vs Liquid crystal",
        "Shadow vs Reflection"
      ];
      const corePersonal = [
        "Should I quit my job?", 
        "How to find peace?", 
        "Meaning of my shadow?",
        "Where is the source of my longing?",
        "Should I trust the chaos within?",
        "Is now the time for a radical departure?"
      ];
      const coreKnowledge = [
        "History of Silk Road", 
        "Black hole causality", 
        "Color theory origin",
        "Etymology of the word 'Chance'",
        "The geometry of sacred architecture",
        "The philosophy of Russian Constructivism"
      ];
      const all = [...corePhilosophical, ...coreComparisons, ...corePersonal, ...coreKnowledge];
      setSuggestions(all.sort(() => 0.5 - Math.random()).slice(0, 6));
    };
    rotate();
    const interval = setInterval(rotate, 120000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const saved = localStorage.getItem('oracle_history');
    if (saved) setHistory(JSON.parse(saved));
  }, []);

  useEffect(() => localStorage.setItem('oracle_history', JSON.stringify(history)), [history]);

  useEffect(() => {
    if (state.status === 'REVEALED' && state.response) handleImageRegen();
  }, [theme]);

  const stopAudio = () => {
    if (audioSourceRef.current) { try { audioSourceRef.current.stop(); } catch(e) {} audioSourceRef.current = null; }
    if (audioContextRef.current) { audioContextRef.current.close(); audioContextRef.current = null; }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    if (/[а-яА-ЯЁё]/.test(val) && uiLanguage !== 'RU') setUiLanguage('RU');
    else if (/[a-zA-Z]/.test(val) && uiLanguage !== 'EN') setUiLanguage('EN');
  };

  const handleImageRegen = async () => {
    if (!state.response) return;
    setIsImageLoading(true);
    try {
      const result = await regenerateOracleImage(state.response, theme, state.chaosScore);
      setState(prev => ({
        ...prev,
        response: prev.response ? { ...prev.response, base64Image: result.image, imageStyleLabel: result.label, imageUrl: result.url } : null
      }));
    } catch (e) { console.error(e); } finally { setIsImageLoading(false); }
  };

  const runQuery = async (queryText: string) => {
    if (!queryText) return;
    setState(s => ({ ...s, status: 'THINKING', query: queryText }));
    try {
      const response = await consultOracle(queryText, state.chaosScore, theme, uiLanguage);
      setState(s => ({ ...s, status: 'REVEALED', response }));
      setHistory(prev => [{ id: Date.now().toString(), query: queryText, response, timestamp: Date.now(), logicScore: state.logicScore, chaosScore: state.chaosScore }, ...prev].slice(0, 20));
    } catch (e) { 
      setState(s => ({ ...s, status: 'ERROR', error: e instanceof Error ? e.message : 'Void Paradox.' })); 
    }
  };

  const saveArtifactAsImage = async () => {
    if (!captureRef.current) return;
    setShowSaveOptions(false);
    try {
      await new Promise(r => setTimeout(r, 100));
      const canvas = await html2canvas(captureRef.current, { backgroundColor: isRenoir ? '#0f0505' : '#ffffff', useCORS: true, scale: 2 });
      const link = document.createElement('a');
      link.download = `oracle-${Date.now()}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    } catch (e) { console.error(e); }
  };

  const activeAnalysis = (() => {
    const r = state.response;
    if (!r) return "";
    if (activeFramework === 'DEFAULT') return r.detailedAnalysis || r.verdict;
    const keyMap: any = { 'PSYCHOANALYSIS': 'psychoanalysis', 'GESTALT': 'gestalt', 'RUSSIAN': 'russian_philosophy', 'GERMAN': 'german_philosophy', 'EXISTENTIAL': 'existential', 'THEOLOGICAL': 'theological', 'BUDDHIST': 'buddhist', 'POST_MODERN': 'post_modern' };
    const framework = (r.perspectives as any)?.[keyMap[activeFramework]];
    return framework?.analysis || framework?.verdict || r.detailedAnalysis || r.verdict;
  })();

  const NavButton = ({ onClick, children, className = "" }: any) => (
    <button onClick={onClick} className={`w-11 h-11 rounded-full border flex items-center justify-center backdrop-blur-xl transition-all shadow-xl active:scale-95 ${isRenoir ? 'bg-amber-950/40 border-amber-900/20 text-amber-100' : 'bg-white/40 border-black/5 text-black'} ${className}`}>{children}</button>
  );

  const handleSpeakerToggle = async () => {
    const targetMute = !isMuted; setIsMuted(targetMute);
    if (targetMute) stopAudio();
    else if (state.response) {
      setIsTtsLoading(true);
      try {
        const { context, source } = await speakText(activeAnalysis, uiLanguage);
        audioContextRef.current = context; audioSourceRef.current = source;
        source.onended = () => { setIsMuted(true); setIsTtsLoading(false); };
      } catch (e) { setIsMuted(true); } finally { setIsTtsLoading(false); }
    }
  };

  const GlobalUI = (
    <>
      <div className="fixed top-4 left-4 z-[500] flex gap-3">
        {state.status !== 'IDLE' && <NavButton onClick={() => { stopAudio(); setState(s => ({ ...s, status: 'IDLE' })); }}><Icons.ArrowLeft /></NavButton>}
        <NavButton onClick={handleSpeakerToggle} className={!isMuted ? 'ring-2 ring-red-500' : 'opacity-40'}><Icons.Speaker muted={isMuted} loading={isTtsLoading}/></NavButton>
      </div>
      <div className="fixed top-4 right-4 z-[500] flex gap-3 items-center">
        <div className={`flex p-1 rounded-full border backdrop-blur-xl ${isRenoir ? 'bg-amber-950/40 border-amber-900/20' : 'bg-white/40 border-black/5'}`}>
          <button onClick={() => setUiLanguage(l => l === 'EN' ? 'RU' : 'EN')} className="w-8 h-8 rounded-full text-[9px] font-black">{uiLanguage}</button>
          <button onClick={() => setTheme(t => t === 'SUPREMATIST' ? 'IMPRESSIONIST' : 'SUPREMATIST')} className={`px-3 h-8 rounded-full text-[9px] font-black ${isRenoir ? 'bg-amber-700 text-white' : 'bg-black text-white'}`}>
            {theme === 'SUPREMATIST' ? 'Mode A' : 'Mode B'}
          </button>
        </div>
        <NavButton onClick={() => setShowHistory(true)}><Icons.History /></NavButton>
      </div>
    </>
  );

  if (state.status === 'ERROR') return (
    <div className={`h-screen flex flex-col items-center justify-center p-8 text-center ${isRenoir ? 'bg-[#0f0505] text-amber-100' : 'bg-white text-black'}`}>
       <h1 className="text-2xl font-black uppercase mb-4">Paradox Encountered</h1>
       <p className="text-xs opacity-60 mb-8">{state.error}</p>
       <button onClick={() => setState(s => ({ ...s, status: 'IDLE' }))} className="px-8 py-3 border border-current font-black uppercase text-[10px]">Recalibrate</button>
    </div>
  );

  if (state.status === 'THINKING') return <LoadingScreen theme={theme} language={uiLanguage} />;

  if (state.status === 'REVEALED' && state.response) {
    const r = state.response;
    const imageSrc = r.base64Image ? `data:image/png;base64,${r.base64Image}` : r.imageUrl;
    return (
      <div className={`min-h-screen pt-24 pb-12 px-4 md:px-8 overflow-y-auto ${isRenoir ? 'bg-[#0f0505] text-amber-100 font-serif' : 'bg-white text-black font-sans'}`}>
        {GlobalUI}
        <div ref={captureRef} className="max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-12">
          <div className="flex flex-col items-center sticky top-24">
            <RatioIndicator logicScore={state.logicScore} chaosScore={state.chaosScore} category={r.category as any} theme={theme} language={uiLanguage} />
            <div className={`w-full aspect-square border overflow-hidden shadow-2xl ${isRenoir ? 'border-amber-900/20 rounded-3xl' : 'border-black/5'}`}>
              <img src={imageSrc} className="w-full h-full object-cover" crossOrigin="anonymous" />
            </div>
          </div>
          <div className="space-y-6">
            <h1 className="text-2xl lg:text-3xl font-black uppercase tracking-tighter leading-tight whitespace-pre-wrap">{r.title}</h1>
            <div className={`p-6 border ${isRenoir ? 'bg-[#1e0a0a] border-amber-900/10 rounded-2xl' : 'bg-white border-black/5'}`}>
               <h3 className="text-[10px] font-black uppercase opacity-40 mb-3">{t.verdict}</h3>
               <p className="text-xs md:text-sm leading-relaxed whitespace-pre-wrap">{activeAnalysis}</p>
            </div>
            <div className="flex flex-col gap-3">
               <button onClick={() => setShowFullVerdict(true)} className={`py-4 text-[10px] font-black uppercase tracking-[0.2em] rounded-xl ${isRenoir ? 'bg-amber-900 text-white' : 'bg-black text-white'}`}>{t.readVerdict}</button>
               <button onClick={() => setState(s => ({ ...s, status: 'IDLE' }))} className="py-4 text-[10px] border border-current font-black uppercase rounded-xl">{t.newQuery}</button>
            </div>
            <div className="pt-6 border-t border-current/10 flex flex-wrap gap-4 items-center">
               <span className="text-[9px] font-black uppercase opacity-30">Context:</span>
               {r.sources?.map((s, i) => <a key={i} href={s.uri} target="_blank" className="text-[9px] border-b border-current/20 font-black">{s.title}</a>)}
               <a href={`https://www.google.com/search?q=${encodeURIComponent(r.title)}`} target="_blank" className="text-[9px] font-black border border-current/20 px-3 py-1 rounded-full hover:bg-black hover:text-white">{t.studyFurther}</a>
            </div>
          </div>
        </div>
        {showFullVerdict && (
          <div className="fixed inset-0 z-[1000] bg-black/90 backdrop-blur-lg flex items-center justify-center p-4 lg:p-12" onClick={() => setShowFullVerdict(false)}>
            <div className={`w-full max-w-6xl max-h-[90vh] overflow-y-auto p-8 lg:p-16 text-white rounded-[2rem] border border-white/10 ${isRenoir ? 'bg-amber-950/95' : 'bg-zinc-950/95'}`} onClick={e => e.stopPropagation()}>
               <h2 className="text-3xl font-black mb-8 border-b border-white/10 pb-6 whitespace-pre-wrap">{r.title}</h2>
               <div className="space-y-8 font-serif">
                  {activeAnalysis.split('\n\n').map((p: string, i: number) => (
                    <p key={i} className="text-lg leading-relaxed first-letter:text-5xl first-letter:font-black first-letter:float-left first-letter:mr-3">{p}</p>
                  ))}
               </div>
               <button onClick={() => setShowFullVerdict(false)} className="mt-12 px-12 py-4 border border-white/20 hover:bg-white hover:text-black font-black uppercase tracking-widest text-[10px] rounded-xl">Back</button>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className={`h-screen w-full flex flex-col items-center justify-center p-4 relative ${isRenoir ? 'bg-[#0f0505] text-amber-100 font-serif' : 'bg-white text-black font-sans'}`}>
      <ThemeBackground theme={theme} />
      {GlobalUI}
      <div className="z-10 w-full max-w-2xl text-center space-y-8">
        <h1 className="text-2xl md:text-3xl lg:text-4xl font-light uppercase tracking-tighter leading-[0.9] whitespace-pre-wrap select-none">
          {t.title}
        </h1>
        <form onSubmit={e => { e.preventDefault(); runQuery(inputRef.current?.value || ""); }} className="space-y-8">
          <input ref={inputRef} placeholder={t.placeholder} onChange={handleInputChange} className="w-full bg-transparent border-b border-current/20 p-4 text-center text-xl font-light focus:outline-none focus:border-current transition-all" />
          <button type="submit" className={`w-24 h-24 font-black uppercase transition-all hover:scale-110 active:scale-90 shadow-2xl ${theme === 'SUPREMATIST' ? 'rounded-none' : 'rounded-full'} ${isRenoir ? 'bg-amber-900 text-white' : 'bg-black text-white'}`}>{t.ask}</button>

          <div className="flex flex-wrap justify-center gap-2">
            {suggestions.map(s => (
