        <div className={`flex p-1 rounded-full border backdrop-blur-xl ${isRenoir ? 'bg-amber-950/40 border-amber-900/20' : 'bg-white/40 border-black/5'}`}>
          <button onClick={() => setUiLanguage(l => l === 'EN' ? 'RU' : 'EN')} className="w-8 h-8 rounded-full text-[9px] font-black">{uiLanguage}</button>
          <button onClick={() => setTheme(t => t === 'SUPREMATIST' ? 'IMPRESSIONIST' : 'SUPREMATIST')} className={`px-3 h-8 rounded-full text-[9px] font-black ${isRenoir ? 'bg-amber-700 text-white' : 'bg-black text-white'}`}>
            {theme === 'SUPREMATIST' ? 'Mode A' : 'Mode B'}
          </button>
        </div>
        <NavButton onClick={() => setShowHistory(true)}><Icons.History /></NavButton>
      </div>
    </>
  );

  const FrameworksRow = () => {
    const list: FrameworkType[] = ['DEFAULT', 'PSYCHOANALYSIS', 'GESTALT', 'RUSSIAN', 'GERMAN', 'EXISTENTIAL', 'THEOLOGICAL', 'BUDDHIST', 'POST_MODERN'];
    return (
      <div className="flex flex-wrap gap-1 py-4 border-b border-current/10 mb-4 justify-center lg:justify-start">
        {list.map(f => (
          <button 
            key={f} 
            onClick={() => setActiveFramework(f)}
            className={`px-3 py-1.5 rounded-full text-[8px] font-black uppercase transition-all ${activeFramework === f ? (isRenoir ? 'bg-amber-900 text-white' : 'bg-black text-white') : 'opacity-40 hover:opacity-100 border border-current/10'}`}
          >
            {(t.frameworks as any)[f]}
          </button>
        ))}
      </div>
    );
  };

  if (state.status === 'ERROR') return (
    <div className={`h-screen flex flex-col items-center justify-center p-8 text-center ${isRenoir ? 'bg-[#0f0505] text-amber-100' : 'bg-white text-black'}`}>
       <h1 className="text-2xl font-black uppercase mb-4 tracking-tighter">Paradox Encountered</h1>
       <p className="text-xs opacity-60 mb-8 max-w-xs mx-auto">{state.error}</p>
       <button onClick={() => setState(s => ({ ...s, status: 'IDLE' }))} className="px-8 py-3 border border-current font-black uppercase text-[10px] rounded-full">Recalibrate</button>
    </div>
  );

  if (state.status === 'THINKING') return <LoadingScreen theme={theme} language={uiLanguage} />;

  if (state.status === 'REVEALED' && state.response) {
    const r = state.response;
    const imageSrc = r.base64Image ? `data:image/png;base64,${r.base64Image}` : r.imageUrl;
    return (
      <div className={`min-h-screen pt-24 pb-12 px-6 md:px-8 overflow-y-auto ${isRenoir ? 'bg-[#0f0505] text-amber-100 font-serif' : 'bg-white text-black font-sans'}`}>
        {GlobalUI}
        <div ref={captureRef} className="max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 lg:gap-16 items-start">

          <div className="flex flex-col items-center lg:sticky lg:top-24 order-1">
            <div className="w-full max-w-[240px] md:max-w-sm">
              <RatioIndicator logicScore={state.logicScore} chaosScore={state.chaosScore} category={r.category as any} theme={theme} language={uiLanguage} />
              <div className={`w-full aspect-square border overflow-hidden shadow-2xl ${isRenoir ? 'border-amber-900/20 rounded-3xl' : 'border-black/5'}`}>
                <img src={imageSrc} className="w-full h-full object-cover" crossOrigin="anonymous" alt="Oracle Visual" />
              </div>
            </div>
          </div>

          <div className="flex flex-col items-center lg:items-start order-2 w-full max-w-[480px] lg:max-w-none mx-auto">
            <h1 className="text-xl md:text-3xl font-black uppercase tracking-tighter leading-tight whitespace-pre-wrap text-center lg:text-left mb-6">
              {r.title}
            </h1>

            <FrameworksRow />

            <div className={`p-6 border w-full newspaper-column mb-6 ${isRenoir ? 'bg-[#1e0a0a] border-amber-900/10 rounded-2xl' : 'bg-white border-black/5'}`}>
               <h3 className="text-[9px] font-black uppercase opacity-40 mb-3 text-center lg:text-left">{t.verdict}</h3>
               <p className="text-sm md:text-base leading-relaxed whitespace-pre-wrap text-justify lg:text-left">
                  {activeAnalysis}
               </p>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 w-full">
               <button onClick={() => setShowFullVerdict(true)} className={`py-4 text-[9px] font-black uppercase tracking-widest rounded-xl transition-all active:scale-95 shadow-lg ${isRenoir ? 'bg-amber-900 text-white' : 'bg-black text-white'}`}>
                {t.readVerdict}
               </button>
               <button onClick={saveArtifactAsImage} className="py-4 text-[9px] border border-current/20 font-black uppercase rounded-xl transition-all active:scale-95 flex items-center justify-center gap-2">
                <Icons.Download /> {t.saveArtifact}
               </button>
               <button onClick={() => setState(s => ({ ...s, status: 'IDLE' }))} className="py-4 text-[9px] border border-current font-black uppercase rounded-xl transition-all active:scale-95">
                {t.newQuery}
               </button>
            </div>

            <div className="pt-6 mt-6 border-t border-current/10 flex flex-wrap gap-4 items-center justify-center lg:justify-start w-full">
               <span className="text-[9px] font-black uppercase opacity-30">Sources:</span>
               {r.sources?.map((s, i) => (
                <a key={i} href={s.uri} target="_blank" rel="noopener noreferrer" className="text-[9px] border-b border-current/20 font-black hover:opacity-70">
                  {s.title}
                </a>
               ))}
               <a href={`https://www.google.com/search?q=${encodeURIComponent(r.title)}`} target="_blank" rel="noopener noreferrer" className="text-[9px] font-black border border-current/20 px-3 py-1 rounded-full hover:bg-black hover:text-white transition-all">
                {t.studyFurther}
               </a>
            </div>
          </div>
        </div>

        {showFullVerdict && (
          <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4 lg:p-12" onClick={() => setShowFullVerdict(false)}>
            <div className={`w-full max-w-5xl max-h-[90vh] overflow-y-auto p-8 lg:p-16 text-white rounded-[2rem] border border-white/10 ${isRenoir ? 'bg-amber-950/95' : 'bg-zinc-950/95'}`} onClick={e => e.stopPropagation()}>
               <h2 className="text-3xl lg:text-4xl font-black mb-10 border-b border-white/10 pb-6 whitespace-pre-wrap tracking-tighter">
                {r.title}
               </h2>
               <div className="space-y-10 font-serif max-w-3xl mx-auto">
                  {activeAnalysis.split('\n\n').map((p: string, i: number) => (
                    <p key={i} className="text-lg lg:text-xl leading-relaxed first-letter:text-6xl first-letter:font-black first-letter:float-left first-letter:mr-4 first-letter:leading-[0.8] text-justify">
                      {p}
                    </p>
                  ))}
               </div>
               <div className="mt-16 flex justify-center">
                <button onClick={() => setShowFullVerdict(false)} className="px-16 py-4 border border-white/20 hover:bg-white hover:text-black font-black uppercase tracking-widest text-[10px] rounded-xl transition-all">
                  {uiLanguage === 'EN' ? 'CLOSE PERSPECTIVE' : 'ЗАКРЫТЬ'}
                </button>
               </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className={`h-screen w-full flex flex-col items-center justify-center p-4 relative overflow-hidden ${isRenoir ? 'bg-[#0f0505] text-amber-100 font-serif' : 'bg-white text-black font-sans'}`}>
      <ThemeBackground theme={theme} />
      {GlobalUI}
      <div className="z-10 w-full max-w-2xl text-center space-y-10">
        <h1 className="text-2xl md:text-3xl font-light uppercase tracking-tighter leading-[0.9] whitespace-pre-wrap select-none transition-all">
          {t.title}
        </h1>
        <form onSubmit={e => { e.preventDefault(); runQuery(inputRef.current?.value || ""); }} className="space-y-10">
          <input 
            ref={inputRef} 
            placeholder={t.placeholder} 
            onChange={handleInputChange} 
            className="w-full bg-transparent border-b border-current/20 p-4 text-center text-xl md:text-2xl font-light focus:outline-none focus:border-current transition-all" 
          />
          <div className="flex justify-center">
            <button type="submit" className={`w-28 h-28 md:w-32 md:h-32 font-black uppercase transition-all hover:scale-105 active:scale-95 shadow-2xl flex items-center justify-center ${theme === 'SUPREMATIST' ? 'rounded-none' : 'rounded-full'} ${isRenoir ? 'bg-amber-900 text-white' : 'bg-black text-white'}`}>
              <span className="text-lg md:text-xl tracking-widest">{t.ask}</span>
            </button>
          </div>

          <div className="flex flex-wrap justify-center gap-2 max-w-lg mx-auto px-4">
            {suggestions.map(s => (
              <button 
                key={s} 
                type="button" 
                onClick={() => { if(inputRef.current) inputRef.current.value = s; runQuery(s); }} 
                className="px-4 py-2 text-[8px] md:text-[9px] border border-current rounded-full font-black opacity-30 hover:opacity-100 transition-opacity duration-300 active:scale-95"
              >
                {s}
              </button>
            ))}
          </div>
        </form>
      </div>
      <footer className="absolute bottom-4 text-[9px] opacity-10 tracking-[0.5em] font-black select-none uppercase">
        {t.footer}
      </footer>
    </div>
  );
};

export interface OracleSource {
  title: string;
  uri: string;
}

export interface ComparisonOption {
  title: string;
  description: string;
  score: number;
}

export interface Perspective {
  verdict: string;
  analysis: string;
}

export interface OracleResponse {
  type: 'SINGLE' | 'COMPARISON';
  title: string; 
  verdict: string; 
  category: 'PRODUCT' | 'MEDIA' | 'LIFE' | 'TECH' | 'RELATIONAL' | 'KNOWLEDGE' | 'FUTURE' | 'BOOKS' | 'MUSIC' | 'ARCHITECTURE' | 'GAMING' | 'SCIENCE' | 'GASTRONOMY';
  genre?: string;
  reasoning: string;
  sources?: OracleSource[];
  base64Image?: string; 
  imageUrl?: string;
  imageStyleLabel?: string;
  language?: 'EN' | 'RU';
  isFallback?: boolean;
  perspectives?: {
    psychoanalysis?: Perspective;
    gestalt?: Perspective;
    russian_philosophy?: Perspective;
    german_philosophy?: Perspective;
    existential?: Perspective;
    theological?: Perspective;
    buddhist?: Perspective;
    post_modern?: Perspective;
  };
  detailedAnalysis?: string; 
  comparison?: {
    optionA: ComparisonOption;
    optionB: ComparisonOption;
    winner: 'A' | 'B';
  };
}

export interface HistoryItem {
  id: string;
  query: string;
  response: OracleResponse;
  timestamp: number;
  logicScore: number;
  chaosScore: number;
}

export interface OracleState {
  status: 'IDLE' | 'THINKING' | 'REVEALED' | 'ERROR';
  query: string;
  response: OracleResponse | null;
  logicScore: number; 
  chaosScore: number; 
  error?: string;
  attempts: number;
  isFallbackActive?: boolean;
}

import React, { useState, useRef, useEffect } from 'react';
import html2canvas from 'html2canvas';
import { OracleState, OracleResponse, HistoryItem } from './types';
import { consultOracle, regenerateOracleImage, translateOracleResponse, speakText } from './services/oracleService';
import { RatioIndicator } from './components/RatioIndicator';
import { LoadingScreen } from './components/LoadingScreen';
import { ThemeBackground } from './components/ThemeBackground';

type Theme = 'SUPREMATIST' | 'IMPRESSIONIST';
type Language = 'EN' | 'RU';
type FrameworkType = 'DEFAULT' | 'PSYCHOANALYSIS' | 'GESTALT' | 'RUSSIAN' | 'GERMAN' | 'EXISTENTIAL' | 'THEOLOGICAL' | 'BUDDHIST' | 'POST_MODERN';

const TRANSLATIONS = {
  EN: {
    ask: "ASK", placeholder: "What do you seek?", logic: "Logic", chaos: "Chaos", voidEmpty: "The void is silent", return: "Return", winner: "THE WINNER", verdict: "THE VERDICT", readVerdict: "FULL PERSPECTIVE", closeVerdict: "CLOSE", saveArtifact: "SAVE ARTIFACT", saveCard: "Save Card", saveImage: "Save Picture", newQuery: "NEW QUERY", sources: "Evidence Found", studyFurther: "Study Further", imageLost: "Vision lost.", title: "The Oracle\nof Chance", footer: "Anti-Algorithm v1.5", errorMsg: "A paradox has occurred.", history: "HISTORY", optionA: "Option A", optionB: "Option B", translating: "Translating...",
    manualCalibration: "Manual Calibration",
    backupWarning: "backup generator used - pollinations",
    frameworks: { DEFAULT: "Ontological", PSYCHOANALYSIS: "Freud", GESTALT: "Gestalt", RUSSIAN: "Russian", GERMAN: "German", EXISTENTIAL: "Existential", THEOLOGICAL: "Theology", BUDDHIST: "Zen", POST_MODERN: "Post-Mod" }
  },
  RU: {
    ask: "СПРОСИТЬ", placeholder: "Что вы ищете?", logic: "Логика", chaos: "Хаос", voidEmpty: "Пустота безмолвна", return: "Назад", winner: "ПОБЕДИТЕЛЬ", verdict: "ВЕРДИКТ", readVerdict: "ПОЛНЫЙ ВИД", closeVerdict: "ЗАКРЫТЬ", saveArtifact: "АРТЕФАКТ", saveCard: "Сохранить Карту", saveImage: "Сохранить Фото", newQuery: "НОВЫЙ ЗАПРОС", sources: "Улики", studyFurther: "Изучить подробнее", imageLost: "Видение потеряно.", title: "Оракул\nСлучая", footer: "Анти-Алгоритм v1.5", errorMsg: "Произошел парадокс.", history: "ИСТОРИЯ", optionA: "Вариант А", optionB: "Вариант Б", translating: "Перевод...",
    manualCalibration: "Ручная калибровка",
    backupWarning: "используется резервный генератор - pollinations",
    frameworks: { DEFAULT: "Ядро", PSYCHOANALYSIS: "Фрейд", GESTALT: "Гештальт", RUSSIAN: "Русская", GERMAN: "Немецкая", EXISTENTIAL: "Экзистенц", THEOLOGICAL: "Теология", BUDDHIST: "Дзен", POST_MODERN: "Пост-Мод" }
  }
};

const Icons = {
  ArrowLeft: () => <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>,
  History: () => <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>,
  Speaker: ({ muted, loading }: { muted: boolean, loading: boolean }) => (
    <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24" className={loading ? 'animate-pulse' : ''}>
      {muted ? <><path d="M11 5L6 9H2v6h4l5 4V5z"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/></> : <><path d="M11 5l-5 4H2v6h4l5 4V5z"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/></>}
    </svg>
  ),
  Close: () => <svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M6 18L18 6M6 6l12 12"/></svg>,
  Download: () => <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3"/></svg>,
  Settings: () => <svg width="12" height="12" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M12 3v3M12 18v3M3 12h3M18 12h3M5.6 5.6l2.1 2.1M16.3 16.3l2.1 2.1M5.6 18.4l2.1-2.1M16.3 7.7l2.1-2.1"/></svg>,
  ExternalLink: () => <svg width="12" height="12" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6M15 3h6v6M10 14L21 3"/></svg>,
  Search: () => <svg width="12" height="12" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/></svg>
};

export const App: React.FC = () => {
  const [theme, setTheme] = useState<Theme>('SUPREMATIST');
  const [uiLanguage, setUiLanguage] = useState<Language>('EN');
  const [initialChaos] = useState(() => Math.floor(Math.random() * 80) + 10);
  const [state, setState] = useState<OracleState>({ status: 'IDLE', query: '', response: null, logicScore: 100 - initialChaos, chaosScore: initialChaos, attempts: 0 });
  const [activeFramework, setActiveFramework] = useState<FrameworkType>('DEFAULT');
  const [isMuted, setIsMuted] = useState(true);
  const [isTtsLoading, setIsTtsLoading] = useState(false);
  const [showFullVerdict, setShowFullVerdict] = useState(false);
  const [isImageLoading, setIsImageLoading] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [isManual, setIsManual] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [suggestions, setSuggestions] = useState<string[]>([]);

  const audioContextRef = useRef<AudioContext | null>(null);
  const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const captureRef = useRef<HTMLDivElement>(null);

  const isRenoir = theme === 'IMPRESSIONIST';
  const t = TRANSLATIONS[uiLanguage];

  useEffect(() => {
    const rotate = () => {
      const core = [
        "Does the algorithm have a soul?", "Is memory resistance?", "The ethics of eternity",
        "Vinyl vs Streaming", "City vs Wilderness", "Manual vs Automatic",
        "Should I quit my job?", "Meaning of my shadow?", "Trust the chaos?",
        "History of Silk Road", "Black hole causality", "Color theory origin"
      ];
      setSuggestions(core.sort(() => 0.5 - Math.random()).slice(0, 6));
    };
    rotate();
    const interval = setInterval(rotate, 120000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const saved = localStorage.getItem('oracle_history');
    if (saved) setHistory(JSON.parse(saved));
  }, []);

  useEffect(() => localStorage.setItem('oracle_history', JSON.stringify(history)), [history]);

  useEffect(() => {
    if (state.status === 'REVEALED' && state.response) handleImageRegen();
  }, [theme]);

  const stopAudio = () => {
    if (audioSourceRef.current) { try { audioSourceRef.current.stop(); } catch(e) {} audioSourceRef.current = null; }
    if (audioContextRef.current) { audioContextRef.current.close(); audioContextRef.current = null; }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    if (/[а-яА-ЯЁё]/.test(val) && uiLanguage !== 'RU') setUiLanguage('RU');
    else if (/[a-zA-Z]/.test(val) && uiLanguage !== 'EN') setUiLanguage('EN');
  };

  const handleImageRegen = async () => {
    if (!state.response) return;
    setIsImageLoading(true);
    try {
      const result = await regenerateOracleImage(state.response, theme, state.chaosScore);
      setState(prev => ({
        ...prev,
        response: prev.response ? { ...prev.response, base64Image: result.image, imageStyleLabel: result.label, imageUrl: result.url, isFallback: result.isFallback || prev.response.isFallback } : null
      }));
    } catch (e) { console.error(e); } finally { setIsImageLoading(false); }
  };

  const runQuery = async (queryText: string) => {
    if (!queryText) return;
    setState(s => ({ ...s, status: 'THINKING', query: queryText }));
    try {
      const response = await consultOracle(queryText, state.chaosScore, theme, uiLanguage);
      setState(s => ({ ...s, status: 'REVEALED', response }));
      setHistory(prev => [{ id: Date.now().toString(), query: queryText, response, timestamp: Date.now(), logicScore: state.logicScore, chaosScore: state.chaosScore }, ...prev].slice(0, 20));
      setActiveFramework('DEFAULT');
    } catch (e) { 
      setState(s => ({ ...s, status: 'ERROR', error: e instanceof Error ? e.message : 'Void Paradox.' })); 
    }
  };

  const saveArtifactAsImage = async () => {
    if (!captureRef.current) return;
    try {
      await new Promise(r => setTimeout(r, 100));
      const canvas = await html2canvas(captureRef.current, { 
        backgroundColor: isRenoir ? '#0f0505' : '#ffffff', 
        useCORS: true, 
        scale: 2 
      });
      const link = document.createElement('a');
      link.download = `oracle-artifact-${Date.now()}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    } catch (e) { console.error("Capture failed:", e); }
  };

  const activeAnalysis = (() => {
    const r = state.response;
    if (!r) return "";
    if (activeFramework === 'DEFAULT') return r.detailedAnalysis || r.verdict;
    const keyMap: any = { 
      'PSYCHOANALYSIS': 'psychoanalysis', 'GESTALT': 'gestalt', 
      'RUSSIAN': 'russian_philosophy', 'GERMAN': 'german_philosophy', 
      'EXISTENTIAL': 'existential', 'THEOLOGICAL': 'theological', 
      'BUDDHIST': 'buddhist', 'POST_MODERN': 'post_modern' 
    };
    const framework = (r.perspectives as any)?.[keyMap[activeFramework]];
    return framework?.analysis || framework?.verdict || r.detailedAnalysis || r.verdict;
  })();

  const NavButton = ({ onClick, children, className = "" }: any) => (
    <button onClick={onClick} className={`w-11 h-11 rounded-full border flex items-center justify-center backdrop-blur-xl transition-all shadow-xl active:scale-95 ${isRenoir ? 'bg-amber-950/40 border-amber-900/20 text-amber-100' : 'bg-white/40 border-black/5 text-black'} ${className}`}>{children}</button>
  );

  const handleSpeakerToggle = async () => {
    const targetMute = !isMuted; setIsMuted(targetMute);
    if (targetMute) stopAudio();
    else if (state.response) {
      setIsTtsLoading(true);
      try {
        const { context, source } = await speakText(activeAnalysis, uiLanguage);
        audioContextRef.current = context; audioSourceRef.current = source;
        source.onended = () => { setIsMuted(true); setIsTtsLoading(false); };
      } catch (e) { setIsMuted(true); } finally { setIsTtsLoading(false); }
    }
  };

  const GlobalUI = (
    <>
      {state.response?.isFallback && (
        <div className={`fixed top-0 left-0 w-full z-[600] py-1 text-center text-[8px] font-black uppercase tracking-widest ${isRenoir ? 'bg-amber-900 text-white' : 'bg-red-600 text-white'}`}>
          {t.backupWarning}
        </div>
      )}
      <div className="fixed top-4 left-4 z-[500] flex gap-3">
        {state.status !== 'IDLE' && <NavButton onClick={() => { stopAudio(); setState(s => ({ ...s, status: 'IDLE' })); }}><Icons.ArrowLeft /></NavButton>}
        <NavButton onClick={handleSpeakerToggle} className={!isMuted ? 'ring-2 ring-red-500' : 'opacity-40'}><Icons.Speaker muted={isMuted} loading={isTtsLoading}/></NavButton>
      </div>
      <div className="fixed top-4 right-4 z-[500] flex gap-3 items-center">
        <div className={`flex p-1 rounded-full border backdrop-blur-xl ${isRenoir ? 'bg-amber-950/40 border-amber-900/20' : 'bg-white/40 border-black/5'}`}>
          <button onClick={() => setUiLanguage(l => l === 'EN' ? 'RU' : 'EN')} className="w-8 h-8 rounded-full text-[9px] font-black">{uiLanguage}</button>
          <button onClick={() => setTheme(t => t === 'SUPREMATIST' ? 'IMPRESSIONIST' : 'SUPREMATIST')} className={`px-3 h-8 rounded-full text-[9px] font-black ${isRenoir ? 'bg-amber-700 text-white' : 'bg-black text-white'}`}>
            {theme === 'SUPREMATIST' ? 'Mode A' : 'Mode B'}
          </button>
        </div>
        <NavButton onClick={() => setShowHistory(true)}><Icons.History /></NavButton>
      </div>
    </>
  );

