import { GoogleGenAI, Modality, Type } from "@google/genai";
import { OracleResponse, OracleSource } from "../types";

// Declare process to satisfy TypeScript compiler
declare var process: {
  env: {
    API_KEY: string;
  };
};

const textModel = "gemini-3-pro-preview"; 

function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

function cleanJsonResponse(text: string): string {
  if (!text) return "{}";
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) return jsonMatch[0];
  let cleaned = text.trim();
  cleaned = cleaned.replace(/^```json\s*/, '').replace(/```$/, '');
  return cleaned.trim();
}

const perspectiveSchema = {
  type: Type.OBJECT,
  properties: {
    verdict: { type: Type.STRING },
    analysis: { type: Type.STRING }
  },
  required: ["verdict", "analysis"]
};

const oracleResponseSchema = {
  type: Type.OBJECT,
  properties: {
    type: { type: Type.STRING },
    category: { type: Type.STRING },
    title: { type: Type.STRING },
    verdict: { type: Type.STRING },
    detailedAnalysis: { type: Type.STRING },
    perspectives: {
      type: Type.OBJECT,
      properties: {
        psychoanalysis: perspectiveSchema,
        gestalt: perspectiveSchema,
        russian_philosophy: perspectiveSchema,
        german_philosophy: perspectiveSchema,
        existential: perspectiveSchema,
        theological: perspectiveSchema,
        buddhist: perspectiveSchema,
        post_modern: perspectiveSchema
      }
    }
  },
  required: ["type", "category", "title", "verdict", "detailedAnalysis", "perspectives"]
};

/**
 * Pollinations Text Fallback
 */
async function fallbackTextGeneration(query: string, language: 'EN' | 'RU'): Promise<string> {
    const prompt = `You are the Oracle of Chance. Return ONLY a JSON object answering: "${query}". 
    Format: {
      "type": "SINGLE",
      "category": "LIFE",
      "title": "A Philosophical Title",
      "verdict": "Short summary.",
      "detailedAnalysis": "3-4 long paragraphs about the query, separated by \\n\\n.",
      "perspectives": { 
        "psychoanalysis": {"verdict": "V", "analysis": "A"},
        "gestalt": {"verdict": "V", "analysis": "A"},
        "russian_philosophy": {"verdict": "V", "analysis": "A"},
        "german_philosophy": {"verdict": "V", "analysis": "A"},
        "existential": {"verdict": "V", "analysis": "A"},
        "theological": {"verdict": "V", "analysis": "A"},
        "buddhist": {"verdict": "V", "analysis": "A"},
        "post_modern": {"verdict": "V", "analysis": "A"}
      }
    }
    Language: ${language === 'RU' ? 'Russian' : 'English'}. No markdown code blocks, just raw JSON.`;

    try {
        const response = await fetch(`https://text.pollinations.ai/${encodeURIComponent(prompt)}?json=true`);
        return await response.text();
    } catch (e) {
        throw new Error("Critical Failure: Void Unreachable.");
    }
}

function determineSubStyle(response: OracleResponse, chaosScore: number, mode: 'SUPREMATIST' | 'IMPRESSIONIST'): string {
    const titleLower = response.title?.toLowerCase() || "";
    const isMedia = response.category === 'MEDIA' || titleLower.includes('movie');
    const isBook = response.category === 'BOOKS' || titleLower.includes('book');

    if (isMedia) return chaosScore <= 50 ? (mode === 'SUPREMATIST' ? 'BAUHAUS_POSTER' : 'VINTAGE_POSTER') : 'CINEMATIC_SHOT';
    if (isBook) return chaosScore <= 50 ? (mode === 'SUPREMATIST' ? 'CONSTRUCTIVISM' : 'VINTAGE_POSTER') : 'LITERARY_POSTER';

    if (mode === 'SUPREMATIST') return chaosScore < 40 ? 'CUBISM' : (chaosScore < 70 ? 'CONSTRUCTIVISM' : 'SUPREMATISM');
    return chaosScore < 40 ? 'IMPRESSIONISM' : (chaosScore < 70 ? 'POST_IMPRESSIONISM' : 'SYMBOLISM');
}

function buildImagePrompt(response: OracleResponse, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST', subStyle: string): string {
  const safeTitle = response.title || "Vision"; 
  return `Artistic interpretation of "${safeTitle}" in style of ${subStyle}. Non-literal representation. Deep atmosphere.`;
}

async function generateImageWithFallback(prompt: string): Promise<{ image?: string; url?: string; isFallback?: boolean }> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts: [{ text: prompt }] },
            config: { imageConfig: { aspectRatio: "1:1" } }
        });
        const candidate = response.candidates?.[0];
        if (candidate?.content?.parts) {
            for (const part of candidate.content.parts) {
                if (part.inlineData) return { image: part.inlineData.data, isFallback: false };
            }
        }
    } catch (e) { 
        console.warn("Image Gemini quota reached."); 
    }
    const seed = Math.floor(Math.random() * 1000000);
    return { url: `https://image.pollinations.ai/prompt/${encodeURIComponent(prompt)}?width=1024&height=1024&nologo=true&seed=${seed}`, isFallback: true };
}

export const speakText = async (text: string, language: 'EN' | 'RU' = 'EN') => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: language === 'RU' ? 'Puck' : 'Kore' } } }
            }
        });
        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (base64Audio) {
            const context = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
            const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), context, 24000, 1);
            const source = context.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(context.destination);
            source.start();
            return { context, source };
        }
    } catch (e) { console.error(e); }
    throw new Error("Audio failed");
};

export const translateOracleResponse = async (data: OracleResponse, targetLang: 'EN' | 'RU'): Promise<OracleResponse> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const payload = { ...data };
    const originalImage = payload.base64Image;
    const originalUrl = payload.imageUrl;
    delete payload.base64Image;
    delete payload.imageUrl;

    try {
        const response = await ai.models.generateContent({
            model: textModel,
            contents: `Translate this JSON to ${targetLang}. Preserve philosophy. JSON: ${JSON.stringify(payload)}`,
            config: { 
              responseMimeType: "application/json",
              responseSchema: oracleResponseSchema
            }
        });
        const parsed = JSON.parse(cleanJsonResponse(response.text || "{}"));
        return { ...parsed, base64Image: originalImage, imageUrl: originalUrl, language: targetLang, isFallback: data.isFallback };
    } catch (e) {
        return { ...data, language: targetLang };
    }
};

export const consultOracle = async (query: string, chaosPercentage: number, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST' = 'SUPREMATIST', language: 'EN' | 'RU' = 'EN'): Promise<OracleResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let isTextFallback = false;
  let responseText = "";
  let fetchedSources: OracleSource[] = [];

  try {
    const response = await ai.models.generateContent({
      model: textModel,
      contents: query,
      config: { 
        systemInstruction: `You are The Oracle of Chance. Answer in ${language}. Use double newlines for paragraphs.`, 
        tools: [{ googleSearch: {} }], 
        temperature: (chaosPercentage / 100) + 0.1 
      },
    });
    responseText = response.text || "{}";
    const candidate = response.candidates?.[0];
    if (candidate?.groundingMetadata?.groundingChunks) {
      fetchedSources = candidate.groundingMetadata.groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({ title: chunk.web.title || "Link", uri: chunk.web.uri }));
    }
  } catch (e) {
    console.warn("Text Gemini quota reached, using Pollinations.");
    isTextFallback = true;
    responseText = await fallbackTextGeneration(query, language);
  }

  try {
    const parsed = JSON.parse(cleanJsonResponse(responseText)) as OracleResponse;
    const subStyle = determineSubStyle(parsed, chaosPercentage, artStyle);
    parsed.imageStyleLabel = subStyle.replace('_', '-');

    const imgResult = await generateImageWithFallback(buildImagePrompt(parsed, artStyle, subStyle));

    return { 
      ...parsed, 
      base64Image: imgResult.image, 
      imageUrl: imgResult.url, 
      sources: fetchedSources.length > 0 ? fetchedSources : (parsed.sources || []),
      language,
      isFallback: isTextFallback || imgResult.isFallback
    };
  } catch (e) {
    throw new Error("Revelation Parsing Error.");
  }
};

export const regenerateOracleImage = async (response: OracleResponse, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST', chaosScore: number) => {
    const subStyle = determineSubStyle(response, chaosScore, artStyle);
    const result = await generateImageWithFallback(buildImagePrompt(response, artStyle, subStyle));
    return { image: result.image, url: result.url, label: subStyle.replace('_', '-'), isFallback: result.isFallback };
};

