    if (saved) {
      try { setHistory(JSON.parse(saved)); } catch(e) { console.error("History parse failed"); }
    }
  }, []);

  useEffect(() => {
    // To avoid QuotaExceededError, we prune the heavy base64Image data for older items before saving to storage
    const pruned = history.map((item, index) => {
      if (index > 0) { // Keep image for the most recent item only, or strip all to be safe
         const { base64Image, ...rest } = item.response;
         return { ...item, response: rest };
      }
      return item;
    });
    try {
      localStorage.setItem('oracle_history', JSON.stringify(pruned));
    } catch (e) {
      console.warn("Storage quota exceeded. Saving failed.");
      // If it still fails, try saving without any images
      const fullyPruned = history.map(item => {
        const { base64Image, ...rest } = item.response;
        return { ...item, response: rest };
      });
      try { localStorage.setItem('oracle_history', JSON.stringify(fullyPruned)); } catch(e2) {}
