                </div>
                <div className="text-sm md:text-base font-bold uppercase truncate">{item.query}</div>
              </button>
            ))}
         </div>
      </div>
    </div>
  );

  if (state.status === 'ERROR') return (
    <div className={`h-screen flex flex-col items-center justify-center p-8 text-center ${isRenoir ? 'bg-[#0f0505] text-amber-100' : 'bg-white text-black'}`}>
       <h1 className="text-2xl font-black uppercase mb-4 tracking-widest">Paradox Encountered</h1>
       <p className="text-xs opacity-60 mb-8 max-w-xs">{state.error}</p>
       <button onClick={() => setState(s => ({ ...s, status: 'IDLE' }))} className="px-8 py-3 border border-current font-black uppercase text-[10px] rounded-full">Recalibrate</button>
    </div>
  );

  if (state.status === 'THINKING') return <LoadingScreen theme={theme} language={uiLanguage} />;

  if (state.status === 'REVEALED' && state.response) {
    const r = state.response;
    const imageSrc = r.base64Image ? `data:image/png;base64,${r.base64Image}` : (r.imageUrl || "");
    return (
      <div className={`min-h-screen pt-20 pb-10 px-4 md:px-8 overflow-y-auto ${isRenoir ? 'bg-[#0f0505] text-amber-100 font-serif' : 'bg-white text-black font-sans'}`}>
        {GlobalUI}
        {HistorySidebar}
        <div ref={captureRef} className="max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 lg:gap-16 items-start">
          <div className="flex flex-col items-center lg:sticky lg:top-24 order-1">
            <div className="w-full max-w-[240px] md:max-w-sm">
              <RatioIndicator logicScore={state.logicScore} chaosScore={state.chaosScore} category={r.category as any} theme={theme} language={uiLanguage} />
              <div className={`relative w-full aspect-square border overflow-hidden shadow-2xl ${isRenoir ? 'border-amber-900/20 rounded-3xl' : 'border-black/5'}`}>
                {isImageLoading && <div className="absolute inset-0 z-20 bg-black/40 backdrop-blur-lg flex items-center justify-center"><div className="w-6 h-6 border-2 border-white border-t-transparent rounded-full animate-spin"/></div>}
                {imageSrc ? <img src={imageSrc} className="w-full h-full object-cover" crossOrigin="anonymous" alt="Oracle Vision" /> : <div className="h-full flex items-center justify-center opacity-20 text-[9px] font-black uppercase tracking-widest">{t.imageLost}</div>}
              </div>
            </div>
          </div>
          <div className="flex flex-col items-center lg:items-start order-2 w-full">
            <h1 className="text-xl md:text-3xl font-black uppercase tracking-tighter leading-tight whitespace-pre-wrap text-center lg:text-left mb-6">{r.title}</h1>
            <div className={`p-6 border w-full mb-6 max-w-[65ch] ${isRenoir ? 'bg-[#1e0a0a] border-amber-900/10 rounded-2xl' : 'bg-white border-black/5'}`}>
               <div className="flex justify-between items-center mb-4 border-b border-current/10 pb-2">
                 <h3 className="text-[9px] font-black uppercase tracking-widest opacity-40">{t.verdict}</h3>
                 <select value={activeFramework} onChange={(e) => setActiveFramework(e.target.value as FrameworkType)} className="text-[8px] font-black uppercase bg-transparent outline-none cursor-pointer">
                    {Object.keys(t.frameworks).map(k => <option key={k} value={k} className="text-black">{(t.frameworks as any)[k]}</option>)}
                 </select>
               </div>
               <p className="text-xs md:text-sm leading-relaxed whitespace-pre-wrap text-justify">{activeAnalysis}</p>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 w-full">
               <button onClick={() => setShowFullVerdict(true)} className={`py-3.5 text-[9px] font-black uppercase tracking-widest rounded-xl transition-all active:scale-95 shadow-lg ${isRenoir ? 'bg-amber-900 text-white' : 'bg-black text-white'}`}>{t.readVerdict}</button>
               <button onClick={saveArtifactAsImage} className="py-3.5 text-[9px] border border-current font-black uppercase rounded-xl transition-all active:scale-95 flex items-center justify-center gap-2">
                <Icons.Download /> {t.saveArtifact}
               </button>
               <button onClick={() => setState(s => ({ ...s, status: 'IDLE' }))} className="py-3.5 text-[9px] border border-current font-black uppercase rounded-xl transition-all active:scale-95">{t.newQuery}</button>
            </div>
            <div className="pt-6 mt-6 border-t border-current/10 flex flex-wrap gap-4 items-center justify-center lg:justify-start">
               <span className="text-[9px] font-black uppercase tracking-[0.3em] opacity-30">{t.sources}</span>
               {r.sources?.map((s, i) => (
                <a key={i} href={s.uri} target="_blank" rel="noopener noreferrer" className="text-[9px] border-b border-current/20 font-black hover:opacity-70">{s.title}</a>
               ))}
               <a href={`https://www.google.com/search?q=${encodeURIComponent(r.title)}`} target="_blank" rel="noopener noreferrer" className="text-[9px] font-black border border-current/20 px-3 py-1 rounded-full hover:bg-black hover:text-white transition-all shadow-sm">{t.studyFurther}</a>
            </div>
          </div>
        </div>
        {showFullVerdict && (
          <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4 lg:p-12" onClick={() => setShowFullVerdict(false)}>
            <div className={`w-full max-w-5xl max-h-[90vh] overflow-y-auto p-8 lg:p-16 text-white rounded-[2rem] border border-white/10 ${isRenoir ? 'bg-amber-950/95' : 'bg-zinc-950/95'}`} onClick={e => e.stopPropagation()}>
               <h2 className="text-2xl lg:text-4xl font-black mb-10 border-b border-white/10 pb-6 whitespace-pre-wrap">{r.title}</h2>
               <div className="space-y-10 font-serif">
                  {activeAnalysis.split('\n\n').map((p, i) => (
                    <p key={i} className="text-base lg:text-xl leading-relaxed first-letter:text-5xl first-letter:font-black first-letter:float-left first-letter:mr-4 first-letter:leading-[0.8]">{p}</p>
                  ))}
               </div>
               <div className="mt-16 flex justify-center">
                <button onClick={() => setShowFullVerdict(false)} className="px-16 py-4 border border-white/20 hover:bg-white hover:text-black font-black uppercase tracking-widest text-[10px] rounded-xl transition-all">{t.closeVerdict}</button>
               </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className={`h-screen w-full flex flex-col items-center justify-center p-4 overflow-hidden relative ${isRenoir ? 'bg-[#0f0505] text-amber-100 font-serif' : 'bg-white text-black font-sans'}`}>
      <ThemeBackground theme={theme} />
      {GlobalUI}
      {HistorySidebar}
      <div className="z-10 w-full max-w-2xl text-center space-y-10">
        <h1 className="text-xl md:text-3xl font-light uppercase tracking-tighter leading-[0.9] whitespace-pre-wrap select-none">{t.title}</h1>
        <form onSubmit={e => { e.preventDefault(); runQuery(inputRef.current?.value || ""); }} className="space-y-10">
          <input 
            ref={inputRef} placeholder={t.placeholder} onChange={handleInputChange} 
            className="w-full bg-transparent border-b border-current/20 p-4 text-center text-xl md:text-2xl font-light focus:outline-none transition-all" 
          />
          <div className="flex flex-col items-center gap-4">
             <div className="flex flex-col items-center gap-2 w-full">
                <button 
                  type="button" 
                  onClick={() => setIsManual(!isManual)} 
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-[8px] md:text-[9px] font-black uppercase tracking-widest border transition-all shadow-lg hover:scale-105 active:scale-95 ${
                    isManual 
                      ? (isRenoir ? 'bg-amber-100/15 border-amber-100/40 text-amber-100' : 'bg-zinc-100 border-black/40 text-black') 
                      : 'opacity-20 border-current hover:opacity-100'
                  }`}
                >
                  <Icons.Settings /> {t.manualCalibration}
                </button>
                <div className={`w-full max-w-[280px] overflow-hidden transition-all duration-400 ${isManual ? 'max-h-24 opacity-100 mt-1' : 'max-h-0 opacity-0 pointer-events-none'}`}>
                  <div className="p-3 bg-current/5 rounded-2xl border border-current/5 space-y-3 backdrop-blur-sm">
                    <div className="flex justify-between text-[7px] font-black uppercase opacity-50 tracking-widest"><span>{t.logic} {state.logicScore}%</span><span>{t.chaos} {state.chaosScore}%</span></div>
                    <input type="range" min="0" max="100" value={state.chaosScore} onChange={e => { const c = parseInt(e.target.value); setState(s => ({ ...s, chaosScore: c, logicScore: 100 - c })); }} className="w-full h-1 bg-gray-200 rounded-full appearance-none cursor-pointer accent-current hover:brightness-110 transition-all" />
                  </div>
                </div>
              </div>
              <button type="submit" className={`w-24 h-24 md:w-32 md:h-32 font-black uppercase shadow-2xl transition-all hover:scale-105 active:scale-95 flex items-center justify-center ${theme === 'SUPREMATIST' ? 'rounded-none' : 'rounded-full'} ${isRenoir ? 'bg-amber-900 text-white' : 'bg-black text-white'}`}>
                <span className="text-lg md:text-xl tracking-widest">{t.ask}</span>
              </button>
          </div>
          <div className="flex flex-wrap justify-center gap-2 max-w-lg mx-auto">
            {suggestions.map(s => (
              <button 
                key={s} 
                type="button" 
                onClick={() => { if(inputRef.current) inputRef.current.value = s; runQuery(s); }} 
                className="px-4 py-2 text-[8px] md:text-[9px] border border-current rounded-full font-black opacity-30 hover:opacity-100 transition-opacity active:scale-95"
              >
                {s}
              </button>
            ))}
          </div>
        </form>
      </div>
      <footer className="absolute bottom-4 text-[9px] opacity-10 tracking-[0.5em] font-black select-none uppercase">{t.footer}</footer>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import html2canvas from 'html2canvas';
import { OracleState, OracleResponse, HistoryItem } from './types';
import { consultOracle, regenerateOracleImage, translateOracleResponse, speakText } from './services/oracleService';
import { RatioIndicator } from './components/RatioIndicator';
import { LoadingScreen } from './components/LoadingScreen';
import { ThemeBackground } from './components/ThemeBackground';

type Theme = 'SUPREMATIST' | 'IMPRESSIONIST';
type Language = 'EN' | 'RU';
type FrameworkType = 'DEFAULT' | 'PSYCHOANALYSIS' | 'GESTALT' | 'RUSSIAN' | 'GERMAN' | 'EXISTENTIAL' | 'THEOLOGICAL' | 'BUDDHIST' | 'POST_MODERN';

const TRANSLATIONS = {
  EN: {
    ask: "ASK", placeholder: "What do you seek?", logic: "Logic", chaos: "Chaos", voidEmpty: "The void is silent", return: "Return", winner: "THE WINNER", verdict: "THE VERDICT", readPerspectives: "ALL PERSPECTIVES", closeVerdict: "CLOSE", saveArtifact: "SAVE ARTEFACT", saveCard: "Save Card", saveImage: "Save Picture", newQuery: "NEW QUERY", sources: "Evidence Found", studyFurther: "Study Further", imageLost: "Vision lost.", title: "The Oracle\nof Chance", footer: "Anti-Algorithm v1.5", errorMsg: "A paradox has occurred.", history: "HISTORY", optionA: "Option A", optionB: "Option B", translating: "Translating...",
    manualCalibration: "Manual Calibration",
    backupWarning: "backup generator used - pollinations",
    frameworks: { DEFAULT: "Ontological Core", PSYCHOANALYSIS: "Psychoanalysis", GESTALT: "Gestalt", RUSSIAN: "Russian Philosophy", GERMAN: "German Philosophy", EXISTENTIAL: "Existentialism", THEOLOGICAL: "Theology", BUDDHIST: "Zen Buddhism", POST_MODERN: "Post-Modernism" }
  },
  RU: {
    ask: "СПРОСИТЬ", placeholder: "Что вы ищете?", logic: "Логика", chaos: "Хаос", voidEmpty: "Пустота безмолвна", return: "Назад", winner: "ПОБЕДИТЕЛЬ", verdict: "ВЕРДИКТ", readPerspectives: "ВСЕ ПЕРСПЕКТИВЫ", closeVerdict: "ЗАКРЫТЬ", saveArtifact: "АРТЕФАКТ", saveCard: "Сохранить Карту", saveImage: "Сохранить Фото", newQuery: "НОВЫЙ ЗАПРОС", sources: "Улики", studyFurther: "Изучить подробнее", imageLost: "Видение потеряно.", title: "Оракул\nСлучая", footer: "Анти-Алгоритм v1.5", errorMsg: "Произошел парадокс.", history: "ИСТОРИЯ", optionA: "Вариант А", optionB: "Вариант Б", translating: "Перевод...",
    manualCalibration: "Ручная калибровка",
    backupWarning: "используется резервный генератор - pollinations",
    frameworks: { DEFAULT: "Ядро", PSYCHOANALYSIS: "Психоанализ", GESTALT: "Гештальт", RUSSIAN: "Русская философия", GERMAN: "Немецкая философия", EXISTENTIAL: "Экзистенциализм", THEOLOGICAL: "Теология", BUDDHIST: "Дзен", POST_MODERN: "Постмодернизм" }
  }
};

const Icons = {
  ArrowLeft: () => <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>,
  History: () => <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>,
  Speaker: ({ muted, loading }: { muted: boolean, loading: boolean }) => (
    <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24" className={loading ? 'animate-pulse' : ''}>
      {muted ? <><path d="M11 5L6 9H2v6h4l5 4V5z"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/></> : <><path d="M11 5l-5 4H2v6h4l5 4V5z"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/></>}
    </svg>
  ),
  Close: () => <svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M6 18L18 6M6 6l12 12"/></svg>,
  Settings: () => <svg width="12" height="12" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M12 3v3M12 18v3M3 12h3M18 12h3M5.6 5.6l2.1 2.1M16.3 16.3l2.1 2.1M5.6 18.4l2.1-2.1M16.3 7.7l2.1-2.1"/></svg>,
  Download: () => <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3"/></svg>,
};

export const App: React.FC = () => {
  const [theme, setTheme] = useState<Theme>('SUPREMATIST');
  const [uiLanguage, setUiLanguage] = useState<Language>('EN');
  const [initialChaos] = useState(() => Math.floor(Math.random() * 80) + 10);
  const [state, setState] = useState<OracleState>({ status: 'IDLE', query: '', response: null, logicScore: 100 - initialChaos, chaosScore: initialChaos, attempts: 0 });
  const [activeFramework, setActiveFramework] = useState<FrameworkType>('DEFAULT');
  const [isMuted, setIsMuted] = useState(true);
  const [isTtsLoading, setIsTtsLoading] = useState(false);
  const [showPerspectivesModal, setShowPerspectivesModal] = useState(false);
  const [isImageLoading, setIsImageLoading] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [isManual, setIsManual] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [suggestions, setSuggestions] = useState<string[]>([]);

  const audioContextRef = useRef<AudioContext | null>(null);
  const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const captureRef = useRef<HTMLDivElement>(null);

  const isRenoir = theme === 'IMPRESSIONIST';
  const t = TRANSLATIONS[uiLanguage];

  useEffect(() => {
    const rotate = () => {
      const core = [
        "Does the algorithm have a soul?", "Memory vs Resistance", "Ethics of eternal recurrence",
        "Minimalism vs Baroque", "City vs Wilderness", "Manual vs Automatic",
        "Should I quit my job?", "Trust the chaos?", "What is time?", "History of Silk Road"
      ];
      setSuggestions(core.sort(() => 0.5 - Math.random()).slice(0, 5));
    };
    rotate();
    const interval = setInterval(rotate, 120000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const saved = localStorage.getItem('oracle_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) { console.error("History reset"); }
    }
  }, []);

  useEffect(() => {
    if (history.length > 0) {
      // PRUNING LOGIC: Remove heavy base64 strings from historical items to prevent QuotaExceededError
      const pruned = history.map((item, index) => {
        // Keep image for top 2 items to ensure smooth transition, prune others
        if (index < 2) return item;
        const { base64Image, ...restResponse } = item.response;
        return { ...item, response: restResponse as OracleResponse };
      });
      try {
        localStorage.setItem('oracle_history', JSON.stringify(pruned));
      } catch (e) {
        // If it fails, strip ALL base64 images from all items
        const strictlyPruned = history.map(item => {
          const { base64Image, ...restResponse } = item.response;
          return { ...item, response: restResponse as OracleResponse };
        });
        localStorage.setItem('oracle_history', JSON.stringify(strictlyPruned));
      }
    }
  }, [history]);

  useEffect(() => {
    if (state.status === 'REVEALED' && state.response) handleImageRegen();
  }, [theme]);

  const stopAudio = () => {
    if (audioSourceRef.current) { try { audioSourceRef.current.stop(); } catch(e) {} audioSourceRef.current = null; }
    if (audioContextRef.current) { audioContextRef.current.close(); audioContextRef.current = null; }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    if (/[а-яА-ЯЁё]/.test(val) && uiLanguage !== 'RU') setUiLanguage('RU');
    else if (/[a-zA-Z]/.test(val) && uiLanguage !== 'EN') setUiLanguage('EN');
  };

  const handleImageRegen = async () => {
    if (!state.response) return;
    setIsImageLoading(true);
    try {
      const result = await regenerateOracleImage(state.response, theme, state.chaosScore);
      setState(prev => ({
        ...prev,
        response: prev.response ? { ...prev.response, base64Image: result.image, imageStyleLabel: result.label, imageUrl: result.url, isFallback: result.isFallback || prev.response.isFallback } : null
      }));
    } catch (e) { console.error(e); } finally { setIsImageLoading(false); }
  };

  const runQuery = async (queryText: string) => {
    if (!queryText) return;
    setState(s => ({ ...s, status: 'THINKING', query: queryText }));
    try {
      const response = await consultOracle(queryText, state.chaosScore, theme, uiLanguage);
      setState(s => ({ ...s, status: 'REVEALED', response }));
      setHistory(prev => [{ id: Date.now().toString(), query: queryText, response, timestamp: Date.now(), logicScore: state.logicScore, chaosScore: state.chaosScore }, ...prev].slice(0, 15));
      setActiveFramework('DEFAULT');
    } catch (e) { 
      setState(s => ({ ...s, status: 'ERROR', error: e instanceof Error ? e.message : 'Paradox in the void.' })); 
    }
  };

  const saveArtifactAsImage = async () => {
    if (!captureRef.current) return;
    try {
      await new Promise(r => setTimeout(r, 100));
      const canvas = await html2canvas(captureRef.current, { 
        backgroundColor: isRenoir ? '#0f0505' : '#ffffff', 
        useCORS: true, 
        scale: 2 
      });
      const link = document.createElement('a');
      link.download = `oracle-artifact-${Date.now()}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    } catch (e) { console.error("Capture failed:", e); }
  };

  const activeAnalysis = (() => {
    const r = state.response;
    if (!r) return "";
    if (activeFramework === 'DEFAULT') return r.detailedAnalysis || r.verdict;
    const keyMap: any = { 
      'PSYCHOANALYSIS': 'psychoanalysis', 'GESTALT': 'gestalt', 
      'RUSSIAN': 'russian_philosophy', 'GERMAN': 'german_philosophy', 
      'EXISTENTIAL': 'existential', 'THEOLOGICAL': 'theological', 
      'BUDDHIST': 'buddhist', 'POST_MODERN': 'post_modern' 
    };
    const framework = (r.perspectives as any)?.[keyMap[activeFramework]];
    return framework?.analysis || framework?.verdict || r.detailedAnalysis || r.verdict;
  })();

  const NavButton = ({ onClick, children, className = "" }: any) => (
    <button onClick={onClick} className={`w-11 h-11 rounded-full border flex items-center justify-center backdrop-blur-xl transition-all shadow-xl active:scale-95 ${isRenoir ? 'bg-amber-950/40 border-amber-900/20 text-amber-100' : 'bg-white/40 border-black/5 text-black'} ${className}`}>{children}</button>
  );

  const handleSpeakerToggle = async () => {
    const targetMute = !isMuted; setIsMuted(targetMute);
    if (targetMute) stopAudio();
    else if (state.response) {
      setIsTtsLoading(true);
      try {
        const { context, source } = await speakText(activeAnalysis, uiLanguage);
        audioContextRef.current = context; audioSourceRef.current = source;
        source.onended = () => { setIsMuted(true); setIsTtsLoading(false); };
      } catch (e) { setIsMuted(true); } finally { setIsTtsLoading(false); }
    }
  };

  const GlobalUI = (
    <>
      {state.response?.isFallback && (
        <div className={`fixed top-0 left-0 w-full z-[600] py-1 text-center text-[8px] font-black uppercase tracking-widest ${isRenoir ? 'bg-amber-900 text-white' : 'bg-red-600 text-white'}`}>
          {t.backupWarning}
        </div>
      )}
      <div className="fixed top-4 left-4 z-[500] flex gap-3">
        {state.status !== 'IDLE' && <NavButton onClick={() => { stopAudio(); setState(s => ({ ...s, status: 'IDLE' })); }}><Icons.ArrowLeft /></NavButton>}
        <NavButton onClick={handleSpeakerToggle} className={!isMuted ? 'ring-2 ring-red-500' : 'opacity-40'}><Icons.Speaker muted={isMuted} loading={isTtsLoading}/></NavButton>
      </div>
      <div className="fixed top-4 right-4 z-[500] flex gap-3 items-center">
        <div className={`flex p-1 rounded-full border backdrop-blur-xl ${isRenoir ? 'bg-amber-950/40 border-amber-900/20' : 'bg-white/40 border-black/5'}`}>
          <button onClick={() => setUiLanguage(l => l === 'EN' ? 'RU' : 'EN')} className="w-8 h-8 rounded-full text-[9px] font-black">{uiLanguage}</button>
          <button onClick={() => setTheme(t => t === 'SUPREMATIST' ? 'IMPRESSIONIST' : 'SUPREMATIST')} className={`px-3 h-8 rounded-full text-[9px] font-black ${isRenoir ? 'bg-amber-700 text-white' : 'bg-black text-white'}`}>
            {theme === 'SUPREMATIST' ? 'Mode A' : 'Mode B'}
          </button>
        </div>
        <NavButton onClick={() => setShowHistory(true)}><Icons.History /></NavButton>
      </div>
    </>
  );

  const HistorySidebar = (
    <div className={`fixed inset-0 z-[1000] flex justify-end transition-all ${showHistory ? 'visible opacity-100' : 'invisible opacity-0'}`}>
      <div className={`fixed inset-0 bg-black/60 backdrop-blur-sm transition-opacity duration-300 ${showHistory ? 'opacity-100' : 'opacity-0'}`} onClick={() => setShowHistory(false)} />
      <div className={`relative z-[1010] w-full max-sm:max-w-full max-w-sm h-full p-6 md:p-12 shadow-2xl overflow-y-auto flex flex-col transition-transform duration-500 transform ${showHistory ? 'translate-x-0' : 'translate-x-full'} ${isRenoir ? 'bg-[#1e0a0a] text-amber-100 border-l border-amber-900/10' : 'bg-white text-black border-l border-black/5'}`}>
         <div className="flex justify-between items-center mb-10">
            <h2 className="text-xl md:text-2xl font-black uppercase tracking-tighter">{t.history}</h2>
            <button onClick={() => setShowHistory(false)} className="p-2 hover:rotate-90 transition-transform bg-current/5 rounded-full"><Icons.Close /></button>
         </div>
         <div className="space-y-6 flex-1">
            {history.length === 0 ? (
              <div className="text-center py-24 opacity-20 text-[10px] font-black uppercase tracking-widest">{t.voidEmpty}</div>
            ) : history.map(item => (
              <button key={item.id} onClick={() => { stopAudio(); setState({ ...state, status: 'REVEALED', response: item.response, query: item.query, logicScore: item.logicScore, chaosScore: item.chaosScore }); setShowHistory(false); }} className="block w-full text-left p-6 border border-current/10 rounded-3xl hover:bg-current/5 hover:border-current/20 transition-all group active:scale-95 shadow-sm">
                <div className="text-[9px] opacity-40 mb-2 font-black tracking-widest uppercase flex justify-between items-center">
                  <span>{new Date(item.timestamp).toLocaleTimeString()}</span>
                  <span className="opacity-0 group-hover:opacity-100 transition-opacity">→</span>
                </div>
                <div className="text-base font-bold uppercase truncate">{item.query}</div>
              </button>
            ))}
         </div>
      </div>
    </div>
  );

  if (state.status === 'ERROR') return (
    <div className={`h-screen flex flex-col items-center justify-center p-8 text-center ${isRenoir ? 'bg-[#0f0505] text-amber-100 font-serif' : 'bg-white text-black font-sans'}`}>
       <h1 className="text-2xl font-black uppercase mb-4 tracking-tighter">Paradox Encountered</h1>
       <p className="text-xs opacity-60 mb-8 max-w-xs mx-auto">{state.error}</p>
       <button onClick={() => setState(s => ({ ...s, status: 'IDLE' }))} className="px-8 py-3 border border-current font-black uppercase text-[10px] rounded-full">Recalibrate</button>
    </div>
  );

  if (state.status === 'THINKING') return <LoadingScreen theme={theme} language={uiLanguage} />;

  if (state.status === 'REVEALED' && state.response) {
    const r = state.response;
    const imageSrc = r.base64Image ? `data:image/png;base64,${r.base64Image}` : r.imageUrl;
    const perspectivesList = [
      { id: 'psychoanalysis', label: t.frameworks.PSYCHOANALYSIS },
      { id: 'gestalt', label: t.frameworks.GESTALT },
      { id: 'russian_philosophy', label: t.frameworks.RUSSIAN },
      { id: 'german_philosophy', label: t.frameworks.GERMAN },
      { id: 'existential', label: t.frameworks.EXISTENTIAL },
      { id: 'theological', label: t.frameworks.THEOLOGICAL },
      { id: 'buddhist', label: t.frameworks.BUDDHIST },
      { id: 'post_modern', label: t.frameworks.POST_MODERN },
    ];

    return (
      <div className={`min-h-screen pt-24 pb-12 px-6 md:px-8 overflow-y-auto ${isRenoir ? 'bg-[#0f0505] text-amber-100 font-serif' : 'bg-white text-black font-sans'}`}>
        {GlobalUI}
        {HistorySidebar}
        <div ref={captureRef} className="max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 lg:gap-16 items-start">

          <div className="flex flex-col items-center lg:sticky lg:top-24 order-1">
            <div className="w-full max-w-[280px] md:max-w-sm">
              <RatioIndicator logicScore={state.logicScore} chaosScore={state.chaosScore} category={r.category as any} theme={theme} language={uiLanguage} />
              <div className="relative group">
                <div className={`w-full aspect-square border overflow-hidden shadow-2xl ${isRenoir ? 'border-amber-900/20 rounded-3xl' : 'border-black/10'}`}>
                  {isImageLoading && <div className="absolute inset-0 bg-black/40 backdrop-blur-sm z-10 flex items-center justify-center text-white text-[10px] uppercase font-black tracking-widest">Re-imagining...</div>}
                  <img src={imageSrc} className="w-full h-full object-cover" crossOrigin="anonymous" alt="Oracle Visual" />
                </div>
                {/* Image Genre/Mode Label */}
                <div className={`absolute bottom-4 left-4 right-4 p-2 backdrop-blur-md border border-white/10 rounded-lg text-[8px] font-black uppercase tracking-widest text-center shadow-lg transition-opacity duration-500 opacity-80 group-hover:opacity-100 ${isRenoir ? 'bg-amber-950/60 text-amber-100' : 'bg-white/60 text-black'}`}>
                  {r.imageStyleLabel || 'ABSTRACT'} — {theme === 'SUPREMATIST' ? 'MODE A' : 'MODE B'}
                </div>
              </div>
            </div>
          </div>

          <div className="flex flex-col items-center lg:items-start order-2 w-full max-w-[480px] lg:max-w-none mx-auto">
            <h1 className="text-xl md:text-3xl font-black uppercase tracking-tighter leading-tight whitespace-pre-wrap text-center lg:text-left mb-6">
              {r.title}
            </h1>

            <div className={`p-6 border w-full mb-6 relative ${isRenoir ? 'bg-[#1e0a0a] border-amber-900/10 rounded-2xl shadow-inner' : 'bg-white border-black/5 shadow-sm'}`}>
               <div className="flex justify-between items-center mb-4 border-b border-current/10 pb-2">
                 <h3 className="text-[9px] font-black uppercase opacity-40">{t.verdict}</h3>
                 <select 
                   value={activeFramework} 
                   onChange={(e) => setActiveFramework(e.target.value as FrameworkType)} 
                   className="text-[8px] font-black uppercase bg-transparent outline-none cursor-pointer hover:underline"
                 >
                    {Object.keys(t.frameworks).map(k => <option key={k} value={k} className="text-black">{(t.frameworks as any)[k]}</option>)}
                 </select>
               </div>
               <p className="text-sm md:text-base leading-relaxed whitespace-pre-wrap text-justify lg:text-left transition-opacity duration-300">
                  {activeAnalysis}
               </p>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 w-full">
               <button onClick={() => setShowPerspectivesModal(true)} className={`py-4 text-[9px] font-black uppercase tracking-widest rounded-xl transition-all active:scale-95 shadow-lg ${isRenoir ? 'bg-amber-900 text-white' : 'bg-black text-white'}`}>
                {t.readPerspectives}
               </button>
               <button onClick={saveArtifactAsImage} className="py-4 text-[9px] border border-current/20 font-black uppercase rounded-xl transition-all active:scale-95 flex items-center justify-center gap-2">
                <Icons.Download /> {t.saveArtifact}
               </button>
               <button onClick={() => setState(s => ({ ...s, status: 'IDLE' }))} className="py-4 text-[9px] border border-current font-black uppercase rounded-xl transition-all active:scale-95">
                {t.newQuery}
               </button>
            </div>

            {/* Evidence Section */}
            <div className="pt-8 mt-8 border-t border-current/10 flex flex-col gap-4 w-full text-center lg:text-left">
               <span className="text-[9px] font-black uppercase opacity-30 tracking-[0.4em]">{t.sources}</span>
               <div className="flex flex-wrap gap-x-4 gap-y-2 justify-center lg:justify-start">
                 {r.sources && r.sources.length > 0 ? r.sources.map((s, i) => (
                  <a key={i} href={s.uri} target="_blank" rel="noopener noreferrer" className="text-[9px] border-b border-current/20 font-black hover:opacity-70 transition-opacity">
                    {s.title}
                  </a>
                 )) : <span className="text-[9px] opacity-20">No external data grounded.</span>}
               </div>
               <a href={`https://www.google.com/search?q=${encodeURIComponent(r.title)}`} target="_blank" rel="noopener noreferrer" className="inline-block mt-2 text-[9px] font-black border border-current/20 px-6 py-2 rounded-full hover:bg-black hover:text-white transition-all shadow-sm self-center lg:self-start">
                {t.studyFurther}
               </a>
            </div>
          </div>
        </div>

        {/* FULL SCREEN PERSPECTIVES MODAL */}
        {showPerspectivesModal && (
          <div className="fixed inset-0 z-[1000] bg-black/98 backdrop-blur-3xl overflow-y-auto" onClick={() => setShowPerspectivesModal(false)}>
            <div className="min-h-screen p-6 md:p-20 flex flex-col items-center" onClick={e => e.stopPropagation()}>
               <div className="w-full max-w-4xl flex justify-between items-center mb-20 border-b border-white/10 pb-8">
                  <h2 className="text-2xl md:text-5xl font-black text-white uppercase tracking-tighter leading-[0.85]">{r.title}</h2>
                  <button onClick={() => setShowPerspectivesModal(false)} className="text-white hover:rotate-90 transition-transform p-4"><Icons.Close /></button>
               </div>

               <div className="w-full max-w-4xl space-y-24">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
                    {perspectivesList.map((p, idx) => {
                      const data = (r.perspectives as any)?.[p.id];
                      if (!data) return null;
                      return (
                        <div key={p.id} className="space-y-6">
                           <div className="flex items-center gap-4">
                              <span className="text-[40px] font-black text-white/10">{idx + 1}</span>
                              <h3 className="text-xs font-black text-white uppercase tracking-[0.5em]">{p.label}</h3>
                           </div>
                           <div className="pl-14 space-y-4">
                              <p className="text-white/40 text-[9px] uppercase font-black leading-relaxed border-l border-white/10 pl-4 mb-4">{data.verdict}</p>
                              <p className="text-white/80 text-base md:text-lg leading-relaxed font-serif text-justify md:text-left">
                                {data.analysis}
                              </p>
                           </div>
                        </div>
                      );
                    })}
                  </div>
               </div>

               <div className="mt-40 mb-20">
                <button onClick={() => setShowPerspectivesModal(false)} className="px-20 py-6 border border-white/20 hover:bg-white hover:text-black font-black uppercase tracking-widest text-[10px] rounded-2xl transition-all shadow-2xl">
                  {t.closeVerdict}
                </button>
               </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className={`h-screen w-full flex flex-col items-center justify-center p-4 relative overflow-hidden ${isRenoir ? 'bg-[#0f0505] text-amber-100 font-serif' : 'bg-white text-black font-sans'}`}>
      <ThemeBackground theme={theme} />
      {GlobalUI}
      {HistorySidebar}
      <div className="z-10 w-full max-w-2xl text-center space-y-12">
        <h1 className="text-3xl md:text-4xl font-light uppercase tracking-tighter leading-[0.85] whitespace-pre-wrap select-none transition-all drop-shadow-sm">
          {t.title}
        </h1>
        <form onSubmit={e => { e.preventDefault(); runQuery(inputRef.current?.value || ""); }} className="space-y-12">
          <input 
            ref={inputRef} 
            placeholder={t.placeholder} 
            onChange={handleInputChange} 
            className="w-full bg-transparent border-b border-current/20 p-6 text-center text-xl md:text-3xl font-light focus:outline-none focus:border-current transition-all placeholder:opacity-20" 
          />
          <div className="flex flex-col items-center gap-6">
             <div className="flex flex-col items-center gap-2 w-full">
                <button 
                  type="button" 
                  onClick={() => setIsManual(!isManual)} 
                  className={`flex items-center gap-2 px-6 py-2 rounded-full text-[9px] font-black uppercase tracking-widest border transition-all shadow-lg hover:scale-105 active:scale-95 ${
                    isManual 
                      ? (isRenoir ? 'bg-amber-100/15 border-amber-100/40 text-amber-100' : 'bg-zinc-100 border-black/40 text-black') 
                      : 'opacity-20 border-current hover:opacity-100'
                  }`}
                >
                  <Icons.Settings /> {t.manualCalibration}
                </button>
                <div className={`w-full max-w-[280px] overflow-hidden transition-all duration-400 ease-in-out ${isManual ? 'max-h-32 opacity-100 mt-2' : 'max-h-0 opacity-0 pointer-events-none'}`}>
                  <div className="p-4 bg-current/5 rounded-2xl border border-current/10 space-y-4 backdrop-blur-sm">
                    <div className="flex justify-between text-[8px] font-black uppercase opacity-50 tracking-widest"><span>{t.logic} {state.logicScore}%</span><span>{t.chaos} {state.chaosScore}%</span></div>
                    <input type="range" min="0" max="100" value={state.chaosScore} onChange={e => { const c = parseInt(e.target.value); setState(s => ({ ...s, chaosScore: c, logicScore: 100 - c })); }} className="w-full h-1 bg-current/20 rounded-full appearance-none cursor-pointer accent-current hover:brightness-110 transition-all" />
                  </div>
                </div>
              </div>

              <button type="submit" className={`w-32 h-32 md:w-36 md:h-36 font-black uppercase transition-all hover:scale-110 hover:shadow-[0_0_50px_rgba(0,0,0,0.1)] active:scale-95 shadow-2xl flex items-center justify-center ${theme === 'SUPREMATIST' ? 'rounded-none rotate-3 hover:rotate-0' : 'rounded-full scale-95 hover:scale-100'} ${isRenoir ? 'bg-amber-900 text-white' : 'bg-black text-white'}`}>
                <span className="text-xl md:text-2xl tracking-widest">{t.ask}</span>
              </button>
          </div>

          <div className="flex flex-wrap justify-center gap-3 max-w-lg mx-auto px-4 opacity-50">
            {suggestions.map(s => (
              <button 
                key={s} 
                type="button" 
                onClick={() => { if(inputRef.current) inputRef.current.value = s; runQuery(s); }} 
                className="px-4 py-2 text-[9px] border border-current/20 rounded-full font-black opacity-40 hover:opacity-100 hover:border-current transition-all active:scale-95"
              >
                {s}
              </button>
            ))}
          </div>
        </form>
      </div>
      <footer className="absolute bottom-6 text-[9px] opacity-10 tracking-[0.8em] font-black select-none uppercase">
        {t.footer}
      </footer>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import html2canvas from 'html2canvas';
import { OracleState, OracleResponse, HistoryItem } from './types';
import { consultOracle, regenerateOracleImage, translateOracleResponse, speakText } from './services/oracleService';
import { RatioIndicator } from './components/RatioIndicator';
import { LoadingScreen } from './components/LoadingScreen';
import { ThemeBackground } from './components/ThemeBackground';

type Theme = 'SUPREMATIST' | 'IMPRESSIONIST';
type Language = 'EN' | 'RU';
type FrameworkType = 'DEFAULT' | 'PSYCHOANALYSIS' | 'GESTALT' | 'RUSSIAN' | 'GERMAN' | 'EXISTENTIAL' | 'THEOLOGICAL' | 'BUDDHIST' | 'POST_MODERN';

const TRANSLATIONS = {
  EN: {
    ask: "ASK", placeholder: "What do you seek?", logic: "Logic", chaos: "Chaos", voidEmpty: "The void is silent", return: "Return", winner: "THE WINNER", verdict: "THE VERDICT", readPerspectives: "ALL PERSPECTIVES", closeVerdict: "CLOSE", saveArtifact: "SAVE ARTEFACT", saveCard: "Save Card", saveImage: "Save Picture", newQuery: "NEW QUERY", sources: "Evidence Found", studyFurther: "Study Further", imageLost: "Vision lost.", title: "The Oracle\nof Chance", footer: "Anti-Algorithm v1.5", errorMsg: "A paradox has occurred.", history: "HISTORY", optionA: "Option A", optionB: "Option B", translating: "Translating...",
    manualCalibration: "Manual Calibration",
    backupWarning: "backup generator used - pollinations",
    frameworks: { DEFAULT: "Ontological Core", PSYCHOANALYSIS: "Psychoanalysis", GESTALT: "Gestalt", RUSSIAN: "Russian Philosophy", GERMAN: "German Philosophy", EXISTENTIAL: "Existentialism", THEOLOGICAL: "Theology", BUDDHIST: "Zen Buddhism", POST_MODERN: "Post-Modernism" }
  },
  RU: {
    ask: "СПРОСИТЬ", placeholder: "Что вы ищете?", logic: "Логика", chaos: "Хаос", voidEmpty: "Пустота безмолвна", return: "Назад", winner: "ПОБЕДИТЕЛЬ", verdict: "ВЕРДИКТ", readPerspectives: "ВСЕ ПЕРСПЕКТИВЫ", closeVerdict: "ЗАКРЫТЬ", saveArtifact: "АРТЕФАКТ", saveCard: "Сохранить Карту", saveImage: "Сохранить Фото", newQuery: "НОВЫЙ ЗАПРОС", sources: "Улики", studyFurther: "Изучить подробнее", imageLost: "Видение потеряно.", title: "Оракул\nСлучая", footer: "Анти-Алгоритм v1.5", errorMsg: "Произошел парадокс.", history: "ИСТОРИЯ", optionA: "Вариант А", optionB: "Вариант Б", translating: "Перевод...",
    manualCalibration: "Ручная калибровка",
    backupWarning: "используется резервный генератор - pollinations",
    frameworks: { DEFAULT: "Ядро", PSYCHOANALYSIS: "Психоанализ", GESTALT: "Гештальт", RUSSIAN: "Русская философия", GERMAN: "Немецкая философия", EXISTENTIAL: "Экзистенциализм", THEOLOGICAL: "Теология", BUDDHIST: "Дзен", POST_MODERN: "Постмодернизм" }
  }
};

const Icons = {
  ArrowLeft: () => <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>,
  History: () => <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>,
  Speaker: ({ muted, loading }: { muted: boolean, loading: boolean }) => (
    <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24" className={loading ? 'animate-pulse' : ''}>
      {muted ? <><path d="M11 5L6 9H2v6h4l5 4V5z"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/></> : <><path d="M11 5l-5 4H2v6h4l5 4V5z"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/></>}
    </svg>
  ),
  Close: () => <svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M6 18L18 6M6 6l12 12"/></svg>,
  Settings: () => <svg width="12" height="12" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M12 3v3M12 18v3M3 12h3M18 12h3M5.6 5.6l2.1 2.1M16.3 16.3l2.1 2.1M5.6 18.4l2.1-2.1M16.3 7.7l2.1-2.1"/></svg>,
  Download: () => <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3"/></svg>,
};

export const App: React.FC = () => {
  const [theme, setTheme] = useState<Theme>('SUPREMATIST');
  const [uiLanguage, setUiLanguage] = useState<Language>('EN');
  const [initialChaos] = useState(() => Math.floor(Math.random() * 80) + 10);
  const [state, setState] = useState<OracleState>({ status: 'IDLE', query: '', response: null, logicScore: 100 - initialChaos, chaosScore: initialChaos, attempts: 0 });
  const [activeFramework, setActiveFramework] = useState<FrameworkType>('DEFAULT');
  const [isMuted, setIsMuted] = useState(true);
  const [isTtsLoading, setIsTtsLoading] = useState(false);
  const [showPerspectivesModal, setShowPerspectivesModal] = useState(false);
  const [isImageLoading, setIsImageLoading] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [isManual, setIsManual] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [suggestions, setSuggestions] = useState<string[]>([]);

  const audioContextRef = useRef<AudioContext | null>(null);
  const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const captureRef = useRef<HTMLDivElement>(null);

  const isRenoir = theme === 'IMPRESSIONIST';
  const t = TRANSLATIONS[uiLanguage];

  useEffect(() => {
    const rotate = () => {
      const core = [
        "Does the algorithm have a soul?", "Memory vs Resistance", "Ethics of eternal recurrence",
        "Minimalism vs Baroque", "City vs Wilderness", "Manual vs Automatic",
        "Should I quit my job?", "Trust the chaos?", "What is time?", "History of Silk Road"
      ];
      setSuggestions(core.sort(() => 0.5 - Math.random()).slice(0, 5));
    };
    rotate();
    const interval = setInterval(rotate, 120000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const saved = localStorage.getItem('oracle_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) { console.error("History reset"); }
    }
  }, []);

  useEffect(() => {
    if (history.length > 0) {
      const pruned = history.map((item, index) => {
        if (index < 1) return item; // Keep image for the very last one
        const { base64Image, ...restResponse } = item.response;
        return { ...item, response: restResponse as OracleResponse };
      });
      try {
        localStorage.setItem('oracle_history', JSON.stringify(pruned));
      } catch (e) {
        const strictlyPruned = history.map(item => {
          const { base64Image, ...restResponse } = item.response;
          return { ...item, response: restResponse as OracleResponse };
        });
        localStorage.setItem('oracle_history', JSON.stringify(strictlyPruned));
      }
    }
  }, [history]);

  useEffect(() => {
    if (state.status === 'REVEALED' && state.response) handleImageRegen();
  }, [theme]);

  const stopAudio = () => {
    if (audioSourceRef.current) { try { audioSourceRef.current.stop(); } catch(e) {} audioSourceRef.current = null; }
    if (audioContextRef.current) { audioContextRef.current.close(); audioContextRef.current = null; }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    if (/[а-яА-ЯЁё]/.test(val) && uiLanguage !== 'RU') setUiLanguage('RU');
    else if (/[a-zA-Z]/.test(val) && uiLanguage !== 'EN') setUiLanguage('EN');
  };

  const handleImageRegen = async () => {
    if (!state.response) return;
    setIsImageLoading(true);
    try {
      const result = await regenerateOracleImage(state.response, theme, state.chaosScore);
      setState(prev => ({
        ...prev,
        response: prev.response ? { ...prev.response, base64Image: result.image, imageStyleLabel: result.label, imageUrl: result.url, isFallback: result.isFallback || prev.response.isFallback } : null
      }));
    } catch (e) { console.error(e); } finally { setIsImageLoading(false); }
  };

  const runQuery = async (queryText: string) => {
    if (!queryText) return;
    setState(s => ({ ...s, status: 'THINKING', query: queryText }));
    try {
      const response = await consultOracle(queryText, state.chaosScore, theme, uiLanguage);
      setState(s => ({ ...s, status: 'REVEALED', response }));
      setHistory(prev => [{ id: Date.now().toString(), query: queryText, response, timestamp: Date.now(), logicScore: state.logicScore, chaosScore: state.chaosScore }, ...prev].slice(0, 15));
      setActiveFramework('DEFAULT');
    } catch (e) { 
      setState(s => ({ ...s, status: 'ERROR', error: e instanceof Error ? e.message : 'Paradox in the void.' })); 
    }
  };

  const saveArtifactAsImage = async () => {
    if (!captureRef.current) return;
    try {
      await new Promise(r => setTimeout(r, 100));
      const canvas = await html2canvas(captureRef.current, { backgroundColor: isRenoir ? '#0f0505' : '#ffffff', useCORS: true, scale: 2 });
      const link = document.createElement('a');
      link.download = `oracle-artifact-${Date.now()}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    } catch (e) { console.error("Capture failed:", e); }
  };

  const activeAnalysis = (() => {
    const r = state.response;
    if (!r) return "";
    if (activeFramework === 'DEFAULT') return r.detailedAnalysis || r.verdict;
    const keyMap: any = { 
