                <div className={`w-full py-3 text-center border-t border-b border-current/20 font-black uppercase tracking-widest text-sm ${r.isFallback ? 'animate-pulse' : ''}`}>
                  {t.winner}: {r.comparison.winner === 'A' ? r.comparison.optionA.title : r.comparison.optionB.title}
                </div>
              </div>
            ) : null}

            {/* Verdict Container with Blur Effect */}
            <div className={`p-6 border w-full mb-6 relative transition-all duration-500 ${isTranslating ? 'blur-md opacity-40 scale-[0.98]' : ''} ${isRenoir ? 'bg-[#1e0a0a] border-amber-900/10 rounded-2xl shadow-inner' : 'bg-white border-black/5 shadow-sm'}`}>
               <div className="flex justify-between items-center mb-4 border-b border-current/10 pb-2">
                 <h3 className="text-[9px] font-black uppercase opacity-40">{t.verdict}</h3>
                 <select value={activeFramework} onChange={(e) => setActiveFramework(e.target.value as FrameworkType)} className="text-[8px] font-black uppercase bg-transparent outline-none cursor-pointer">
                    {Object.keys(t.frameworks).map(k => <option key={k} value={k} className="text-black">{(t.frameworks as any)[k]}</option>)}
                 </select>
               </div>
               <p className="text-sm md:text-base leading-relaxed whitespace-pre-wrap text-justify lg:text-left">
                  {activeAnalysis}
               </p>
               {isTranslating && (
                 <div className="absolute inset-0 flex items-center justify-center font-black uppercase tracking-widest text-[10px]">{t.translating}</div>
               )}
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 w-full">
               <button onClick={() => setShowPerspectivesModal(true)} className={`py-4 text-[9px] font-black uppercase tracking-widest rounded-xl transition-all active:scale-95 shadow-lg ${isRenoir ? 'bg-amber-900 text-white' : 'bg-black text-white'}`}>
                {t.readPerspectives}
               </button>
               <button onClick={saveArtifactAsImage} className="py-4 text-[9px] border border-current/20 font-black uppercase rounded-xl transition-all active:scale-95 flex items-center justify-center gap-2">
                <Icons.Download /> {t.saveArtifact}
               </button>
               <button onClick={() => setState(s => ({ ...s, status: 'IDLE' }))} className="py-4 text-[9px] border border-current font-black uppercase rounded-xl transition-all active:scale-95">
                {t.newQuery}
               </button>
            </div>

            {/* Sources always listed */}
            <div className="pt-8 mt-8 border-t border-current/10 flex flex-col gap-4 w-full">
               <span className="text-[9px] font-black uppercase opacity-30 tracking-[0.4em] text-center lg:text-left">{t.sources}</span>
               <div className="flex flex-wrap gap-x-4 gap-y-2 justify-center lg:justify-start">
                 {r.sources && r.sources.length > 0 ? r.sources.map((s, i) => (
                  <a key={i} href={s.uri} target="_blank" rel="noopener noreferrer" className="text-[9px] border-b border-current/20 font-black hover:opacity-70">
                    {s.title}
                  </a>
                 )) : (
                   <span className="text-[9px] opacity-20 italic">No external grounding metadata.</span>
                 )}
               </div>
            </div>
          </div>
        </div>

        {/* HIGH CONTRAST PERSPECTIVES MODAL */}
        {showPerspectivesModal && (
          <div className="fixed inset-0 z-[1000] bg-black overflow-y-auto font-sans" onClick={() => setShowPerspectivesModal(false)}>
            <div className="min-h-screen p-6 md:p-24 flex flex-col items-center" onClick={e => e.stopPropagation()}>
               <div className="w-full max-w-5xl flex justify-between items-end mb-20 border-b-4 border-white pb-8">
                  <h2 className="text-3xl md:text-6xl font-black text-white uppercase tracking-tighter leading-[0.8]">{r.title}</h2>
                  <button onClick={() => setShowPerspectivesModal(false)} className="text-white p-4 hover:scale-110 transition-transform"><Icons.Close /></button>
               </div>

               <div className="w-full max-w-5xl space-y-32">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-x-20 gap-y-32">
                    {perspectivesList.map((p, idx) => {
                      const data = (r.perspectives as any)?.[p.id];
                      if (!data) return null;
                      return (
                        <div key={p.id} className="group">
                           <div className="flex items-baseline gap-4 mb-8">
                              <span className="text-5xl font-black text-white/20 select-none">{(idx + 1).toString().padStart(2, '0')}</span>
                              <h3 className="text-xs font-black text-white uppercase tracking-[0.6em] border-b-2 border-white/40 pb-1">{p.label}</h3>
                           </div>
                           <div className="pl-2 border-l border-white/10">
                              <p className="text-white/40 text-[10px] uppercase font-black tracking-widest mb-6 italic">{data.verdict}</p>
                              <div className="text-white text-lg md:text-xl leading-relaxed text-justify first-letter:text-6xl first-letter:font-black first-letter:float-left first-letter:mr-3 first-letter:leading-[0.7] first-letter:text-white first-letter:mt-1 space-y-4">
                                {data.analysis.split('\n\n').map((para: string, pidx: number) => (
                                  <p key={pidx}>{para}</p>
                                ))}
                              </div>
                           </div>
                        </div>
                      );
                    })}
                  </div>
               </div>

               <div className="mt-48 mb-24">
                <button onClick={() => setShowPerspectivesModal(false)} className="px-24 py-6 bg-white text-black font-black uppercase tracking-widest text-[11px] hover:scale-105 active:scale-95 transition-all shadow-[0_0_50px_rgba(255,255,255,0.2)]">
                  {t.closeVerdict}
                </button>
               </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className={`h-screen w-full flex flex-col items-center justify-center p-4 relative overflow-hidden ${isRenoir ? 'bg-[#0f0505] text-amber-100 font-serif' : 'bg-white text-black font-sans'}`}>
      <ThemeBackground theme={theme} />
      {GlobalUI}
      {HistorySidebar}
      <div className="z-10 w-full max-w-2xl text-center space-y-12">
        <h1 className="text-2xl md:text-4xl font-light uppercase tracking-tighter leading-[0.8] whitespace-pre-wrap select-none drop-shadow-sm">
          {t.title}
        </h1>
        <form onSubmit={e => { e.preventDefault(); runQuery(inputRef.current?.value || ""); }} className="space-y-12">
          <input 
            ref={inputRef} 
            placeholder={t.placeholder} 
            onChange={handleInputChange} 
            className="w-full bg-transparent border-b-2 border-current/10 p-6 text-center text-xl md:text-3xl font-light focus:outline-none focus:border-current transition-all" 
          />
          <div className="flex flex-col items-center gap-6">
             <div className="flex flex-col items-center gap-2 w-full">
                <button type="button" onClick={() => setIsManual(!isManual)} className={`flex items-center gap-2 px-6 py-2 rounded-full text-[9px] font-black uppercase tracking-widest border transition-all shadow-lg ${isManual ? (isRenoir ? 'bg-amber-100/15 border-amber-100/40 text-amber-100' : 'bg-zinc-100 border-black/40 text-black') : 'opacity-20 border-current hover:opacity-100'}`}>
                  <Icons.Settings /> {t.manualCalibration}
                </button>
                <div className={`w-full max-w-[280px] overflow-hidden transition-all duration-400 ease-in-out ${isManual ? 'max-h-32 opacity-100 mt-2' : 'max-h-0 opacity-0 pointer-events-none'}`}>
                  <div className="p-4 bg-current/5 rounded-2xl border border-current/10 space-y-4 backdrop-blur-sm">
                    <div className="flex justify-between text-[8px] font-black uppercase opacity-50 tracking-widest"><span>{t.logic} {state.logicScore}%</span><span>{t.chaos} {state.chaosScore}%</span></div>
                    <input type="range" min="0" max="100" value={state.chaosScore} onChange={e => { const c = parseInt(e.target.value); setState(s => ({ ...s, chaosScore: c, logicScore: 100 - c })); }} className="w-full h-1 bg-current/20 rounded-full appearance-none cursor-pointer accent-current" />
                  </div>
                </div>
              </div>

              <button type="submit" className={`w-32 h-32 md:w-36 md:h-36 font-black uppercase transition-all hover:scale-110 active:scale-95 shadow-2xl flex items-center justify-center ${theme === 'SUPREMATIST' ? 'rounded-none rotate-3 hover:rotate-0' : 'rounded-full scale-95 hover:scale-100'} ${isRenoir ? 'bg-amber-900 text-white' : 'bg-black text-white'}`}>
                <span className="text-xl md:text-2xl tracking-widest">{t.ask}</span>
              </button>
          </div>

          <div className="flex flex-wrap justify-center gap-3 max-w-lg mx-auto opacity-50">
            {suggestions.map(s => (
              <button key={s} type="button" onClick={() => { if(inputRef.current) inputRef.current.value = s; runQuery(s); }} className="px-4 py-2 text-[9px] border border-current/20 rounded-full font-black opacity-40 hover:opacity-100 transition-all">
                {s}
              </button>
            ))}
          </div>
        </form>
      </div>
      <footer className="absolute bottom-6 text-[9px] opacity-10 tracking-[0.8em] font-black select-none uppercase">
        {t.footer}
      </footer>
    </div>
  );
};
